insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('clf-cloud-concepts', 'Cloud Concepts', (select id from public.tracks where slug = 'aws-clf'), 0, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-cloud-concepts'), 'clf-cc-value-of-cloud', 'Giá trị của Cloud', 'junior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-cc-loi-ich-chinh-cloud', (select id from public.topics where slug = 'clf-cc-value-of-cloud'), 'theory', 'junior', 2, 3, 'Cloud computing mang lại những lợi ích chính nào so với mô hình on-premises truyền thống?', 'Cloud giúp chuyển chi phí từ CapEx sang OpEx (trả theo mức dùng), tăng agility để triển khai nhanh, và cung cấp elasticity/scalability gần như vô hạn. Bạn không cần đầu tư trước cho phần cứng, tận dụng economies of scale của AWS để có giá thấp hơn, và có thể mở rộng ra toàn cầu (go global) chỉ trong vài phút.', null, null, null),
  ('clf-cc-capex-vs-opex', (select id from public.topics where slug = 'clf-cc-value-of-cloud'), 'theory', 'junior', 2, 3, 'Phân biệt CapEx và OpEx trong bối cảnh chuyển lên cloud.', 'CapEx (Capital Expenditure) là chi phí đầu tư trước cho tài sản cố định như mua server hay xây data center. OpEx (Operational Expenditure) là chi phí vận hành trả theo mức sử dụng. Cloud chuyển mô hình chi tiêu từ CapEx sang OpEx, giúp tránh đầu tư lớn ban đầu và chỉ trả cho tài nguyên thực dùng (pay-as-you-go).', null, null, null),
  ('clf-cc-tinh-elasticity', (select id from public.topics where slug = 'clf-cc-value-of-cloud'), 'quiz', 'junior', 2, 3, 'Đặc tính nào của cloud cho phép tự động tăng/giảm tài nguyên theo nhu cầu thực tế?', 'Elasticity là khả năng tự động mở rộng (scale out) hoặc thu hẹp (scale in) tài nguyên theo tải thực tế, giúp đáp ứng nhu cầu mà không lãng phí. AWS Auto Scaling là ví dụ điển hình.', 'single_choice', '[{"key":"a","text":"Elasticity"},{"key":"b","text":"Redundancy"},{"key":"c","text":"Colocation"},{"key":"d","text":"Depreciation"}]'::jsonb, '{a}'),
  ('clf-cc-agility-time-to-market', (select id from public.topics where slug = 'clf-cc-value-of-cloud'), 'theory', 'junior', 2, 3, 'Agility trong cloud nghĩa là gì và vì sao nó quan trọng?', 'Agility là khả năng nhanh chóng cung cấp và thử nghiệm tài nguyên mới, chỉ trong vài phút thay vì hàng tuần/tháng như khi mua phần cứng. Điều này giảm time-to-market, khuyến khích thử nghiệm với chi phí thấp, và cho phép doanh nghiệp đổi mới (innovate) nhanh hơn.', null, null, null),
  ('clf-cc-six-advantages', (select id from public.topics where slug = 'clf-cc-value-of-cloud'), 'quiz', 'junior', 3, 3, 'Theo AWS, đâu KHÔNG phải là một trong sáu lợi thế (six advantages) của cloud computing?', 'AWS không cam kết 100% uptime tuyệt đối; SLA của các dịch vụ luôn dưới mức đó. Sáu lợi thế thực sự gồm: đổi CapEx lấy variable expense, hưởng economies of scale, ngừng đoán capacity, tăng tốc độ và agility, ngừng chi tiền vận hành data center, và go global in minutes.', 'single_choice', '[{"key":"a","text":"Trade capital expense for variable expense"},{"key":"b","text":"Benefit from massive economies of scale"},{"key":"c","text":"Go global in minutes"},{"key":"d","text":"Guarantee 100% uptime cho mọi dịch vụ"}]'::jsonb, '{d}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-cloud-concepts'), 'clf-cc-cloud-economics', 'Kinh tế đám mây (Cloud Economics)', 'junior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-cc-economies-of-scale', (select id from public.topics where slug = 'clf-cc-cloud-economics'), 'theory', 'junior', 2, 3, 'Economies of scale giúp giảm chi phí trên cloud như thế nào?', 'Vì AWS gộp nhu cầu sử dụng của hàng trăm nghìn khách hàng, họ đạt quy mô mua sắm rất lớn (economies of scale) và chuyển phần tiết kiệm đó thành giá pay-as-you-go thấp hơn. Khách hàng nhờ đó trả ít hơn so với tự xây dựng và vận hành hạ tầng riêng.', null, null, null),
  ('clf-cc-tco', (select id from public.topics where slug = 'clf-cc-cloud-economics'), 'quiz', 'junior', 2, 3, 'TCO (Total Cost of Ownership) dùng để làm gì khi cân nhắc chuyển lên cloud?', 'TCO ước tính và so sánh tổng chi phí (phần cứng, điện, nhân sự, bảo trì...) giữa mô hình on-premises và cloud, giúp doanh nghiệp ra quyết định di chuyển. AWS Pricing Calculator hỗ trợ ước tính chi phí này.', 'single_choice', '[{"key":"a","text":"So sánh tổng chi phí sở hữu giữa on-premises và cloud"},{"key":"b","text":"Đo độ trễ mạng giữa các Region"},{"key":"c","text":"Quản lý quyền truy cập IAM"},{"key":"d","text":"Mã hóa dữ liệu at rest"}]'::jsonb, '{a}'),
  ('clf-cc-pay-as-you-go', (select id from public.topics where slug = 'clf-cc-cloud-economics'), 'theory', 'junior', 2, 3, 'Mô hình giá pay-as-you-go của AWS hoạt động ra sao?', 'Pay-as-you-go nghĩa là bạn chỉ trả cho tài nguyên thực sự tiêu thụ (compute, storage, data transfer...) mà không cần cam kết trước hay trả phí cố định. Điều này biến chi phí thành variable expense, giúp tối ưu theo nhu cầu và tránh lãng phí do over-provisioning.', null, null, null),
  ('clf-cc-pricing-calculator', (select id from public.topics where slug = 'clf-cc-cloud-economics'), 'quiz', 'junior', 2, 3, 'Công cụ nào giúp ước tính chi phí AWS trước khi triển khai workload?', 'AWS Pricing Calculator cho phép mô hình hóa và ước tính chi phí của các dịch vụ trước khi sử dụng. CloudTrail ghi log API, Inspector quét lỗ hổng, còn Trusted Advisor đưa khuyến nghị tối ưu.', 'single_choice', '[{"key":"a","text":"AWS Pricing Calculator"},{"key":"b","text":"AWS CloudTrail"},{"key":"c","text":"Amazon Inspector"},{"key":"d","text":"AWS Trusted Advisor"}]'::jsonb, '{a}'),
  ('clf-cc-variable-expense', (select id from public.topics where slug = 'clf-cc-cloud-economics'), 'quiz', 'junior', 2, 3, 'Lợi thế ''trade fixed expense for variable expense'' của cloud mang lại điều gì?', 'Cloud biến chi phí cố định (đầu tư data center) thành chi phí biến đổi theo mức tiêu thụ thực tế (pay-as-you-go). Nhờ đó chi phí gắn với nhu cầu kinh doanh và tránh đầu tư dư thừa.', 'single_choice', '[{"key":"a","text":"Chỉ trả theo mức tài nguyên thực dùng thay vì đầu tư cố định trước"},{"key":"b","text":"Cam kết một khoản chi phí cố định hàng năm bất kể mức dùng"},{"key":"c","text":"Loại bỏ hoàn toàn mọi chi phí vận hành"},{"key":"d","text":"Buộc phải mua phần cứng trước 3 năm"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-cloud-concepts'), 'clf-cc-service-deployment-models', 'Mô hình dịch vụ & triển khai', 'junior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-cc-iaas-paas-saas', (select id from public.topics where slug = 'clf-cc-service-deployment-models'), 'theory', 'junior', 3, 3, 'Phân biệt ba mô hình dịch vụ IaaS, PaaS và SaaS.', 'IaaS (Infrastructure as a Service) cung cấp tài nguyên hạ tầng cơ bản như compute, storage, network (vd Amazon EC2) và khách hàng tự quản lý OS trở lên. PaaS (Platform as a Service) quản lý luôn nền tảng vận hành để bạn tập trung vào code (vd AWS Elastic Beanstalk). SaaS (Software as a Service) cung cấp phần mềm hoàn chỉnh qua Internet, người dùng chỉ việc dùng (vd Gmail).', null, null, null),
  ('clf-cc-deployment-models', (select id from public.topics where slug = 'clf-cc-service-deployment-models'), 'quiz', 'junior', 2, 3, 'Doanh nghiệp giữ một phần workload trong data center riêng và kết nối với AWS. Đây là mô hình triển khai nào?', 'Hybrid kết hợp hạ tầng on-premises (hoặc private cloud) với public cloud AWS, thường qua VPN hoặc AWS Direct Connect. Mô hình này phù hợp khi cần giữ một số hệ thống tại chỗ vì lý do tuân thủ hoặc độ trễ.', 'single_choice', '[{"key":"a","text":"Hybrid"},{"key":"b","text":"Cloud (all-in)"},{"key":"c","text":"On-premises thuần túy"},{"key":"d","text":"Multi-account"}]'::jsonb, '{a}'),
  ('clf-cc-hybrid-cloud', (select id from public.topics where slug = 'clf-cc-service-deployment-models'), 'theory', 'junior', 3, 3, 'Khi nào doanh nghiệp nên chọn mô hình hybrid cloud?', 'Hybrid phù hợp khi doanh nghiệp cần giữ một số workload on-premises vì yêu cầu tuân thủ (compliance), độ trễ thấp, hoặc do đã đầu tư hạ tầng legacy, nhưng vẫn muốn tận dụng sự linh hoạt của cloud cho phần còn lại. Kết nối thường dùng AWS Direct Connect hoặc VPN.', null, null, null),
  ('clf-cc-iaas-example', (select id from public.topics where slug = 'clf-cc-service-deployment-models'), 'quiz', 'junior', 2, 3, 'Dịch vụ nào là ví dụ điển hình của mô hình IaaS?', 'Amazon EC2 cung cấp máy chủ ảo (compute) mà bạn tự quản lý OS và phần mềm bên trên, đúng đặc trưng IaaS. Elastic Beanstalk là PaaS, còn Gmail/Salesforce là SaaS.', 'single_choice', '[{"key":"a","text":"Amazon EC2"},{"key":"b","text":"Salesforce CRM"},{"key":"c","text":"Gmail"},{"key":"d","text":"AWS Elastic Beanstalk"}]'::jsonb, '{a}'),
  ('clf-cc-saas-example', (select id from public.topics where slug = 'clf-cc-service-deployment-models'), 'quiz', 'junior', 2, 3, 'Dịch vụ email như Gmail hay Amazon WorkMail thuộc mô hình dịch vụ nào?', 'Email dạng dùng-ngay qua Internet là SaaS (Software as a Service): nhà cung cấp quản lý toàn bộ hạ tầng, nền tảng và ứng dụng, khách hàng chỉ sử dụng và quản lý dữ liệu/người dùng của mình.', 'single_choice', '[{"key":"a","text":"SaaS"},{"key":"b","text":"IaaS"},{"key":"c","text":"PaaS"},{"key":"d","text":"On-premises"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-cloud-concepts'), 'clf-cc-well-architected', 'Well-Architected & Hạ tầng toàn cầu', 'junior', 3, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-cc-well-architected-pillars', (select id from public.topics where slug = 'clf-cc-well-architected'), 'theory', 'junior', 3, 3, 'Kể tên các trụ cột (pillars) của AWS Well-Architected Framework.', 'Well-Architected Framework gồm 6 pillars: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, và Sustainability. Chúng là tập hợp best practices giúp thiết kế kiến trúc an toàn, tin cậy, hiệu quả và tối ưu chi phí trên AWS.', null, null, null),
  ('clf-cc-pillar-cost-optimization', (select id from public.topics where slug = 'clf-cc-well-architected'), 'quiz', 'junior', 2, 3, 'Trụ cột Well-Architected nào tập trung vào việc tránh chi phí không cần thiết và chọn đúng loại tài nguyên?', 'Cost Optimization pillar giúp chạy hệ thống với chi phí thấp nhất có thể, thông qua chọn đúng resource type/size, dùng mô hình giá phù hợp, và loại bỏ tài nguyên lãng phí.', 'single_choice', '[{"key":"a","text":"Cost Optimization"},{"key":"b","text":"Reliability"},{"key":"c","text":"Security"},{"key":"d","text":"Operational Excellence"}]'::jsonb, '{a}'),
  ('clf-cc-region-az', (select id from public.topics where slug = 'clf-cc-well-architected'), 'theory', 'junior', 3, 3, 'Region và Availability Zone (AZ) trong hạ tầng toàn cầu của AWS khác nhau thế nào?', 'Region là một khu vực địa lý riêng biệt (vd us-east-1) chứa nhiều Availability Zone. Mỗi AZ là một hoặc nhiều data center độc lập về nguồn điện, làm mát và mạng, cách nhau đủ xa để cô lập sự cố nhưng vẫn kết nối độ trễ thấp. Triển khai qua nhiều AZ giúp đạt high availability.', null, null, null),
  ('clf-cc-high-availability', (select id from public.topics where slug = 'clf-cc-well-architected'), 'quiz', 'junior', 2, 3, 'Cách nào giúp tăng tính high availability cho ứng dụng trên AWS?', 'Phân bổ tài nguyên trên nhiều Availability Zones giúp ứng dụng chịu được sự cố của một AZ mà vẫn hoạt động; đây là nền tảng của high availability và fault tolerance trên AWS.', 'single_choice', '[{"key":"a","text":"Triển khai trên nhiều Availability Zones"},{"key":"b","text":"Chạy tất cả trên một EC2 instance duy nhất"},{"key":"c","text":"Tắt backup để tiết kiệm chi phí"},{"key":"d","text":"Chỉ dùng một AZ để giảm độ trễ"}]'::jsonb, '{a}'),
  ('clf-cc-edge-locations', (select id from public.topics where slug = 'clf-cc-well-architected'), 'theory', 'junior', 3, 3, 'Edge location và Amazon CloudFront có vai trò gì trong hạ tầng AWS?', 'Edge locations là các điểm hiện diện (points of presence) phân tán toàn cầu, được Amazon CloudFront (CDN) dùng để cache nội dung gần người dùng cuối. Nhờ đó giảm độ trễ (latency) và tăng tốc độ phân phối nội dung so với phục vụ trực tiếp từ Region gốc.', null, null, null)
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('clf-security-compliance', 'Security and Compliance', (select id from public.tracks where slug = 'aws-clf'), 1, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-security-compliance'), 'clf-sc-shared-responsibility', 'Mô hình trách nhiệm chung', 'junior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-sc-shared-responsibility-model', (select id from public.topics where slug = 'clf-sc-shared-responsibility'), 'theory', 'junior', 3, 3, 'Mô hình Shared Responsibility Model của AWS phân chia trách nhiệm bảo mật như thế nào?', 'AWS chịu trách nhiệm bảo mật ''OF the cloud'': hạ tầng vật lý, phần cứng, mạng và phần mềm nền tảng chạy các dịch vụ. Khách hàng chịu trách nhiệm bảo mật ''IN the cloud'': dữ liệu, cấu hình, quản lý IAM, mã hóa, patching OS (với dịch vụ như EC2) và quyền truy cập. Ranh giới cụ thể thay đổi theo loại dịch vụ.', null, null, null),
  ('clf-sc-aws-responsibility', (select id from public.topics where slug = 'clf-sc-shared-responsibility'), 'quiz', 'junior', 2, 3, 'Theo Shared Responsibility Model, việc nào thuộc trách nhiệm của AWS?', 'AWS chịu trách nhiệm bảo mật ''OF the cloud'', bao gồm an ninh vật lý của data center, phần cứng và hạ tầng nền tảng. Các mục còn lại (security group, IAM, mã hóa dữ liệu) là trách nhiệm của khách hàng.', 'single_choice', '[{"key":"a","text":"Bảo mật vật lý của data center"},{"key":"b","text":"Cấu hình security group của khách hàng"},{"key":"c","text":"Quản lý IAM users và passwords"},{"key":"d","text":"Mã hóa dữ liệu khách hàng lưu trong S3"}]'::jsonb, '{a}'),
  ('clf-sc-customer-responsibility', (select id from public.topics where slug = 'clf-sc-shared-responsibility'), 'quiz', 'junior', 2, 3, 'Việc nào sau đây là trách nhiệm của KHÁCH HÀNG trong Shared Responsibility Model?', 'Khách hàng chịu trách nhiệm bảo mật ''IN the cloud'': dữ liệu, phân quyền IAM, cấu hình, mã hóa phía client. Phần cứng, làm mát và hypervisor thuộc về AWS.', 'single_choice', '[{"key":"a","text":"Quản lý dữ liệu và cấu hình quyền truy cập (IAM)"},{"key":"b","text":"Bảo trì phần cứng máy chủ vật lý"},{"key":"c","text":"Vận hành hệ thống làm mát data center"},{"key":"d","text":"Bảo mật hypervisor của nền tảng ảo hóa"}]'::jsonb, '{a}'),
  ('clf-sc-security-of-vs-in', (select id from public.topics where slug = 'clf-sc-shared-responsibility'), 'theory', 'junior', 3, 3, 'Phân biệt ''security OF the cloud'' và ''security IN the cloud''.', '''Security OF the cloud'' là trách nhiệm của AWS đối với hạ tầng nền tảng (phần cứng, mạng, cơ sở vật chất). ''Security IN the cloud'' là trách nhiệm của khách hàng đối với những gì họ đặt lên và cấu hình (dữ liệu, ứng dụng, IAM, OS patching...). Đây là hai vế của Shared Responsibility Model.', null, null, null),
  ('clf-sc-patching-responsibility', (select id from public.topics where slug = 'clf-sc-shared-responsibility'), 'quiz', 'junior', 3, 3, 'Với Amazon EC2, ai chịu trách nhiệm cập nhật bản vá (patch) cho hệ điều hành guest?', 'Với EC2 (IaaS), khách hàng quản lý guest OS nên phải tự patching và cập nhật. Ngược lại, với các dịch vụ managed như Amazon RDS, AWS lo phần patching hạ tầng và OS bên dưới.', 'single_choice', '[{"key":"a","text":"Khách hàng"},{"key":"b","text":"AWS"},{"key":"c","text":"Không ai cần patch EC2"},{"key":"d","text":"Nhà cung cấp phần cứng"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-security-compliance'), 'clf-sc-iam', 'IAM & Quản lý truy cập', 'junior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-sc-iam-overview', (select id from public.topics where slug = 'clf-sc-iam'), 'theory', 'junior', 3, 3, 'IAM (Identity and Access Management) gồm những thành phần chính nào?', 'IAM quản lý danh tính và quyền truy cập vào AWS. Các thành phần chính gồm: Users (danh tính cho người/ứng dụng), Groups (nhóm users cùng quyền), Roles (danh tính tạm thời cấp quyền cho dịch vụ hoặc user liên kết), và Policies (tài liệu JSON định nghĩa quyền allow/deny). IAM là dịch vụ global và miễn phí.', null, null, null),
  ('clf-sc-mfa', (select id from public.topics where slug = 'clf-sc-iam'), 'quiz', 'junior', 2, 3, 'Biện pháp nào thêm một lớp bảo mật ngoài username/password khi đăng nhập AWS?', 'MFA (Multi-Factor Authentication) yêu cầu thêm yếu tố xác thực thứ hai (vd mã OTP từ thiết bị) ngoài mật khẩu, giúp bảo vệ tài khoản ngay cả khi mật khẩu bị lộ. AWS khuyến nghị bật MFA cho root user và các IAM user quan trọng.', 'single_choice', '[{"key":"a","text":"Multi-Factor Authentication (MFA)"},{"key":"b","text":"Elastic IP"},{"key":"c","text":"Security Group"},{"key":"d","text":"CloudFront"}]'::jsonb, '{a}'),
  ('clf-sc-least-privilege', (select id from public.topics where slug = 'clf-sc-iam'), 'theory', 'junior', 2, 3, 'Nguyên tắc least privilege trong IAM nghĩa là gì?', 'Least privilege (đặc quyền tối thiểu) nghĩa là chỉ cấp cho user hoặc role đúng những quyền cần thiết để hoàn thành công việc, không hơn. Điều này giảm bề mặt tấn công và hạn chế thiệt hại nếu thông tin đăng nhập bị lộ. Đây là best practice bảo mật cốt lõi của AWS.', null, null, null),
  ('clf-sc-iam-role', (select id from public.topics where slug = 'clf-sc-iam'), 'quiz', 'junior', 3, 3, 'Cách nào được khuyến nghị để cấp quyền cho một ứng dụng chạy trên EC2 truy cập Amazon S3?', 'Gán IAM Role cho EC2 instance cho phép ứng dụng nhận credentials tạm thời tự động luân chuyển, an toàn hơn nhiều so với nhúng access key cố định vào code. Không bao giờ dùng root credentials cho ứng dụng.', 'single_choice', '[{"key":"a","text":"Gán một IAM Role cho EC2 instance"},{"key":"b","text":"Lưu access key cứng trong mã nguồn"},{"key":"c","text":"Dùng root user credentials"},{"key":"d","text":"Chia sẻ mật khẩu IAM user qua email"}]'::jsonb, '{a}'),
  ('clf-sc-root-user', (select id from public.topics where slug = 'clf-sc-iam'), 'theory', 'junior', 3, 3, 'Vì sao không nên dùng root user cho công việc hàng ngày và nên bảo vệ nó thế nào?', 'Root user có toàn quyền không giới hạn trên account nên rủi ro rất cao nếu bị lộ. AWS khuyến nghị: bật MFA cho root, không tạo access key cho root, chỉ dùng root cho vài tác vụ bắt buộc, và tạo IAM users/roles theo least privilege cho công việc hàng ngày.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-security-compliance'), 'clf-sc-security-services', 'Dịch vụ bảo mật AWS', 'junior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-sc-encryption-kms', (select id from public.topics where slug = 'clf-sc-security-services'), 'theory', 'junior', 3, 3, 'AWS KMS (Key Management Service) dùng để làm gì?', 'AWS KMS là dịch vụ quản lý tập trung các khóa mã hóa (encryption keys) dùng để mã hóa dữ liệu at rest trên nhiều dịch vụ như S3, EBS, RDS. KMS giúp tạo, quản lý, luân chuyển khóa và kiểm soát quyền dùng khóa, thường tích hợp với IAM và CloudTrail để audit.', null, null, null),
  ('clf-sc-shield-waf', (select id from public.topics where slug = 'clf-sc-security-services'), 'quiz', 'junior', 3, 3, 'Hai dịch vụ nào của AWS giúp bảo vệ ứng dụng web khỏi tấn công DDoS và tấn công tầng ứng dụng? (Chọn 2)', 'AWS Shield bảo vệ chống tấn công DDoS, còn AWS WAF (Web Application Firewall) lọc lưu lượng web độc hại như SQL injection, XSS. Athena và Glue là dịch vụ phân tích/ETL, không liên quan chống tấn công.', 'multiple_choice', '[{"key":"a","text":"AWS Shield"},{"key":"b","text":"AWS WAF"},{"key":"c","text":"Amazon Athena"},{"key":"d","text":"AWS Glue"}]'::jsonb, '{a,b}'),
  ('clf-sc-guardduty', (select id from public.topics where slug = 'clf-sc-security-services'), 'theory', 'junior', 3, 3, 'Amazon GuardDuty là dịch vụ gì?', 'Amazon GuardDuty là dịch vụ threat detection dùng machine learning để giám sát liên tục các log (VPC Flow Logs, CloudTrail, DNS logs) nhằm phát hiện hoạt động bất thường hoặc độc hại. Nó cảnh báo về các mối đe dọa như truy cập trái phép hay tài khoản bị xâm nhập mà không cần cài agent.', null, null, null),
  ('clf-sc-inspector', (select id from public.topics where slug = 'clf-sc-security-services'), 'quiz', 'junior', 3, 3, 'Dịch vụ nào tự động quét lỗ hổng bảo mật (vulnerabilities) cho EC2 instances và container images?', 'Amazon Inspector tự động đánh giá và quét lỗ hổng phần mềm cũng như phơi nhiễm mạng cho workloads như EC2 và ECR images. Macie tập trung phát hiện dữ liệu nhạy cảm trong S3, còn CloudWatch là giám sát hiệu năng.', 'single_choice', '[{"key":"a","text":"Amazon Inspector"},{"key":"b","text":"Amazon CloudWatch"},{"key":"c","text":"AWS Artifact"},{"key":"d","text":"Amazon Macie"}]'::jsonb, '{a}'),
  ('clf-sc-secrets-manager', (select id from public.topics where slug = 'clf-sc-security-services'), 'theory', 'junior', 3, 3, 'AWS Secrets Manager giải quyết vấn đề gì?', 'AWS Secrets Manager lưu trữ, quản lý và tự động luân chuyển (rotate) các bí mật như mật khẩu database, API keys, thay vì hard-code chúng trong ứng dụng. Ứng dụng truy xuất secret qua API có kiểm soát bằng IAM, giúp tăng bảo mật và giảm rủi ro lộ thông tin.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-security-compliance'), 'clf-sc-compliance-governance', 'Compliance & Governance', 'junior', 3, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-sc-artifact', (select id from public.topics where slug = 'clf-sc-compliance-governance'), 'theory', 'junior', 3, 3, 'AWS Artifact cung cấp gì cho khách hàng?', 'AWS Artifact là cổng tự phục vụ để tải các báo cáo tuân thủ (compliance reports) và chứng nhận của AWS như SOC, PCI DSS, ISO. Nó cũng cho phép xem và chấp nhận các agreements như BAA. Đây là nguồn tài liệu chứng minh AWS đáp ứng các tiêu chuẩn compliance.', null, null, null),
  ('clf-sc-compliance-programs', (select id from public.topics where slug = 'clf-sc-compliance-governance'), 'quiz', 'junior', 2, 3, 'Khách hàng cần bằng chứng AWS tuân thủ chuẩn PCI DSS để phục vụ audit. Họ nên dùng dịch vụ nào?', 'AWS Artifact cung cấp các báo cáo và chứng nhận compliance (bao gồm PCI DSS) để khách hàng tải phục vụ audit. GuardDuty là threat detection, không cung cấp tài liệu compliance.', 'single_choice', '[{"key":"a","text":"AWS Artifact"},{"key":"b","text":"Amazon GuardDuty"},{"key":"c","text":"AWS Lambda"},{"key":"d","text":"Amazon EC2"}]'::jsonb, '{a}'),
  ('clf-sc-cloudtrail', (select id from public.topics where slug = 'clf-sc-compliance-governance'), 'theory', 'junior', 3, 3, 'AWS CloudTrail ghi lại loại thông tin gì và dùng để làm gì?', 'AWS CloudTrail ghi lại các API calls và hoạt động trên account (ai làm gì, khi nào, từ đâu). Nó phục vụ audit, governance và điều tra bảo mật, giúp truy vết thay đổi và phát hiện hành vi bất thường. Log có thể lưu vào S3 để giữ lâu dài.', null, null, null),
  ('clf-sc-config-vs-cloudtrail', (select id from public.topics where slug = 'clf-sc-compliance-governance'), 'quiz', 'junior', 3, 3, 'Dịch vụ nào giúp đánh giá, ghi nhận và kiểm tra cấu hình (configuration) tài nguyên AWS theo thời gian so với các quy tắc mong muốn?', 'AWS Config theo dõi và ghi lại lịch sử cấu hình của tài nguyên, đồng thời đánh giá xem chúng có tuân thủ các rule mong muốn không. CloudTrail thì tập trung ghi API activity chứ không đánh giá trạng thái cấu hình.', 'single_choice', '[{"key":"a","text":"AWS Config"},{"key":"b","text":"AWS CloudTrail"},{"key":"c","text":"Amazon Inspector"},{"key":"d","text":"AWS Shield"}]'::jsonb, '{a}'),
  ('clf-sc-organizations-scp', (select id from public.topics where slug = 'clf-sc-compliance-governance'), 'theory', 'junior', 3, 3, 'AWS Organizations và Service Control Policies (SCP) hỗ trợ governance như thế nào?', 'AWS Organizations cho phép quản lý tập trung nhiều AWS accounts, nhóm chúng vào Organizational Units (OU) và hưởng consolidated billing. Service Control Policies (SCP) đặt giới hạn quyền tối đa (guardrails) cho các account, đảm bảo không account nào vượt quá chính sách bảo mật/tuân thủ của tổ chức.', null, null, null)
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('clf-technology-services', 'Cloud Technology and Services', (select id from public.tracks where slug = 'aws-clf'), 2, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-technology-services'), 'clf-ts-core-compute', 'Compute cốt lõi', 'junior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-ts-ec2-la-gi', (select id from public.topics where slug = 'clf-ts-core-compute'), 'theory', 'junior', 2, 3, 'Amazon EC2 là gì và nó cung cấp loại tài nguyên nào?', 'Amazon EC2 (Elastic Compute Cloud) là dịch vụ cung cấp virtual server (instance) có thể thay đổi kích thước trong cloud. Bạn kiểm soát OS, CPU, RAM, storage và networking, trả tiền theo lượng dùng. EC2 thuộc mô hình IaaS, phù hợp khi cần toàn quyền kiểm soát compute.', null, null, null),
  ('clf-ts-lambda-serverless', (select id from public.topics where slug = 'clf-ts-core-compute'), 'theory', 'junior', 2, 3, 'AWS Lambda hoạt động theo mô hình serverless như thế nào?', 'AWS Lambda chạy code của bạn để phản hồi event mà không cần provision hay quản lý server. Bạn chỉ trả tiền cho compute time thực tế (tính theo ms) khi function chạy, không trả khi idle. Lambda tự động scale theo số request, phù hợp cho event-driven workload.', null, null, null),
  ('clf-ts-chon-serverless-compute', (select id from public.topics where slug = 'clf-ts-core-compute'), 'quiz', 'junior', 2, 3, 'Dịch vụ compute nào cho phép chạy code mà KHÔNG cần provision hay quản lý server?', 'AWS Lambda là serverless compute: bạn chỉ upload code, AWS tự lo server và scaling. EC2 vẫn yêu cầu quản lý instance; EBS là block storage; VPC là networking.', 'single_choice', '[{"key":"a","text":"Amazon EC2"},{"key":"b","text":"AWS Lambda"},{"key":"c","text":"Amazon EBS"},{"key":"d","text":"Amazon VPC"}]'::jsonb, '{b}'),
  ('clf-ts-container-fargate', (select id from public.topics where slug = 'clf-ts-core-compute'), 'quiz', 'junior', 3, 3, 'Bạn muốn chạy container mà không phải quản lý EC2 server bên dưới. Lựa chọn nào phù hợp nhất?', 'AWS Fargate là serverless compute engine cho container (dùng với ECS/EKS), giúp chạy container mà không cần provision hay quản lý EC2. S3 là storage, Route 53 là DNS, IAM là identity.', 'single_choice', '[{"key":"a","text":"AWS Fargate"},{"key":"b","text":"Amazon S3"},{"key":"c","text":"Amazon Route 53"},{"key":"d","text":"AWS IAM"}]'::jsonb, '{a}'),
  ('clf-ts-auto-scaling-benefit', (select id from public.topics where slug = 'clf-ts-core-compute'), 'quiz', 'junior', 2, 3, 'Lợi ích chính của Amazon EC2 Auto Scaling là gì?', 'EC2 Auto Scaling tự động thêm hoặc bớt số lượng instance dựa trên demand, đảm bảo elasticity và tối ưu chi phí. Nó giúp duy trì hiệu năng khi tải tăng và tiết kiệm khi tải giảm.', 'single_choice', '[{"key":"a","text":"Tự động mã hóa dữ liệu at rest"},{"key":"b","text":"Tự động thêm/bớt instance theo nhu cầu (elasticity)"},{"key":"c","text":"Cung cấp CDN toàn cầu"},{"key":"d","text":"Quản lý người dùng và quyền truy cập"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-technology-services'), 'clf-ts-storage-database', 'Lưu trữ và Cơ sở dữ liệu', 'junior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-ts-s3-object-storage', (select id from public.topics where slug = 'clf-ts-storage-database'), 'theory', 'junior', 2, 3, 'Amazon S3 là loại storage gì và dùng cho mục đích nào?', 'Amazon S3 (Simple Storage Service) là object storage lưu dữ liệu dưới dạng object trong bucket, có độ bền (durability) rất cao (11 số 9). Nó phù hợp cho backup, static website, data lake, lưu trữ file media. S3 truy cập qua API/HTTP, không phải file system hay block device.', null, null, null),
  ('clf-ts-chon-luu-tru-object', (select id from public.topics where slug = 'clf-ts-storage-database'), 'quiz', 'junior', 2, 3, 'Ứng dụng cần lưu trữ hàng triệu ảnh và video với độ bền cao, truy cập qua HTTP. Dịch vụ nào phù hợp nhất?', 'Amazon S3 là object storage lý tưởng để lưu file media với durability cao và truy cập qua HTTP/API. EBS là block storage gắn với EC2; RDS là relational database; Lambda là compute.', 'single_choice', '[{"key":"a","text":"Amazon EBS"},{"key":"b","text":"Amazon S3"},{"key":"c","text":"Amazon RDS"},{"key":"d","text":"AWS Lambda"}]'::jsonb, '{b}'),
  ('clf-ts-ebs-block-storage', (select id from public.topics where slug = 'clf-ts-storage-database'), 'theory', 'junior', 3, 3, 'Amazon EBS khác Amazon S3 như thế nào?', 'Amazon EBS (Elastic Block Store) cung cấp block storage gắn vào một EC2 instance, hoạt động như một ổ đĩa để cài OS hay database. S3 là object storage truy cập qua API, không gắn trực tiếp như ổ đĩa. EBS phù hợp cho dữ liệu cần I/O độ trễ thấp, còn S3 cho lưu trữ object quy mô lớn.', null, null, null),
  ('clf-ts-rds-managed-db', (select id from public.topics where slug = 'clf-ts-storage-database'), 'quiz', 'junior', 2, 3, 'Dịch vụ nào là managed relational database, tự lo patching, backup và replication?', 'Amazon RDS (Relational Database Service) là managed relational database (MySQL, PostgreSQL, SQL Server...) tự động hóa patching, backup và replication. DynamoDB là NoSQL; Redshift là data warehouse; S3 là object storage.', 'single_choice', '[{"key":"a","text":"Amazon DynamoDB"},{"key":"b","text":"Amazon Redshift"},{"key":"c","text":"Amazon RDS"},{"key":"d","text":"Amazon S3"}]'::jsonb, '{c}'),
  ('clf-ts-dynamodb-nosql', (select id from public.topics where slug = 'clf-ts-storage-database'), 'theory', 'junior', 2, 3, 'Amazon DynamoDB là gì và khi nào nên dùng?', 'Amazon DynamoDB là managed NoSQL key-value và document database với hiệu năng single-digit millisecond ở mọi quy mô. Nó serverless, tự scale, phù hợp cho ứng dụng cần throughput cao và schema linh hoạt như gaming, IoT, giỏ hàng. Không dùng khi cần truy vấn quan hệ phức tạp (khi đó chọn RDS).', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-technology-services'), 'clf-ts-networking-global', 'Mạng và Hạ tầng toàn cầu', 'junior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-ts-region-az', (select id from public.topics where slug = 'clf-ts-networking-global'), 'theory', 'junior', 2, 3, 'Phân biệt AWS Region và Availability Zone (AZ).', 'AWS Region là khu vực địa lý riêng biệt (ví dụ us-east-1), mỗi Region gồm nhiều Availability Zone. Mỗi AZ là một hoặc nhiều data center độc lập về điện, mạng, tách biệt vật lý nhưng nối với nhau bằng đường truyền low-latency. Triển khai qua nhiều AZ giúp đạt high availability và fault tolerance.', null, null, null),
  ('clf-ts-chon-region-yeu-to', (select id from public.topics where slug = 'clf-ts-networking-global'), 'quiz', 'junior', 1, 3, 'Yếu tố nào KHÔNG phải là tiêu chí chính khi chọn một AWS Region?', 'Khi chọn Region, cân nhắc latency tới end user, pricing của Region, compliance/data residency, và service availability. Màu sắc console không liên quan.', 'single_choice', '[{"key":"a","text":"Độ trễ (latency) tới người dùng"},{"key":"b","text":"Giá dịch vụ tại Region"},{"key":"c","text":"Yêu cầu tuân thủ/compliance dữ liệu"},{"key":"d","text":"Màu sắc giao diện console"}]'::jsonb, '{d}'),
  ('clf-ts-vpc-basics', (select id from public.topics where slug = 'clf-ts-networking-global'), 'theory', 'junior', 2, 3, 'Amazon VPC là gì?', 'Amazon VPC (Virtual Private Cloud) là mạng ảo cô lập logic trong AWS, nơi bạn triển khai tài nguyên như EC2. Bạn kiểm soát IP range, subnet, route table, và gateway. VPC cho phép tách mạng public và private, kiểm soát traffic ra vào.', null, null, null),
  ('clf-ts-cloudfront-edge', (select id from public.topics where slug = 'clf-ts-networking-global'), 'quiz', 'junior', 2, 3, 'Dịch vụ nào dùng edge location để cache nội dung gần người dùng, giảm latency?', 'Amazon CloudFront là CDN dùng mạng edge location toàn cầu để cache và phân phối nội dung gần người dùng, giảm latency. EC2 là compute, IAM là identity, RDS là database.', 'single_choice', '[{"key":"a","text":"Amazon CloudFront"},{"key":"b","text":"Amazon EC2"},{"key":"c","text":"AWS IAM"},{"key":"d","text":"Amazon RDS"}]'::jsonb, '{a}'),
  ('clf-ts-availability-zone-ha', (select id from public.topics where slug = 'clf-ts-networking-global'), 'theory', 'junior', 2, 3, 'Tại sao nên triển khai ứng dụng qua nhiều Availability Zone?', 'Triển khai qua nhiều AZ giúp ứng dụng chịu lỗi khi một AZ gặp sự cố (mất điện, hỏng data center), vì các AZ tách biệt vật lý. Kết hợp với Elastic Load Balancing, traffic được phân phối sang AZ còn hoạt động, đạt high availability. Đây là best practice thiết kế fault-tolerant.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-technology-services'), 'clf-ts-security-iam', 'Bảo mật và IAM', 'junior', 3, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-ts-iam-la-gi', (select id from public.topics where slug = 'clf-ts-security-iam'), 'theory', 'junior', 2, 3, 'AWS IAM dùng để làm gì?', 'AWS IAM (Identity and Access Management) quản lý ai (user, group, role) được truy cập tài nguyên AWS nào và với quyền gì thông qua policy. IAM cho phép áp dụng least privilege và bật MFA. IAM là dịch vụ toàn cầu (global) và miễn phí.', null, null, null),
  ('clf-ts-iam-mfa-best-practice', (select id from public.topics where slug = 'clf-ts-security-iam'), 'quiz', 'junior', 2, 3, 'Best practice bảo mật nào nên áp dụng cho tài khoản AWS root user?', 'Nên bật MFA (Multi-Factor Authentication) cho root user và chỉ dùng root cho tác vụ bắt buộc, còn lại tạo IAM user/role riêng. Không chia sẻ credential hay dùng root hằng ngày.', 'single_choice', '[{"key":"a","text":"Dùng root user cho mọi tác vụ hằng ngày"},{"key":"b","text":"Bật MFA và hạn chế dùng root user"},{"key":"c","text":"Chia sẻ access key của root cho cả team"},{"key":"d","text":"Tắt hoàn toàn IAM"}]'::jsonb, '{b}'),
  ('clf-ts-shared-responsibility', (select id from public.topics where slug = 'clf-ts-security-iam'), 'theory', 'junior', 3, 3, 'Trình bày ngắn gọn AWS Shared Responsibility Model.', 'Theo Shared Responsibility Model, AWS chịu trách nhiệm bảo mật OF the cloud (hạ tầng vật lý, phần cứng, mạng, ảo hóa), còn khách hàng chịu trách nhiệm bảo mật IN the cloud (dữ liệu, cấu hình, IAM, OS/patch trên EC2, mã hóa). Ranh giới thay đổi tùy loại dịch vụ (IaaS/PaaS/SaaS).', null, null, null),
  ('clf-ts-iam-least-privilege', (select id from public.topics where slug = 'clf-ts-security-iam'), 'quiz', 'junior', 2, 3, 'Nguyên tắc least privilege trong IAM nghĩa là gì?', 'Least privilege nghĩa là chỉ cấp cho user/role đúng những quyền tối thiểu cần thiết để thực hiện nhiệm vụ, giảm rủi ro bảo mật. Cấp quá nhiều quyền hoặc chia sẻ credential đều vi phạm best practice.', 'single_choice', '[{"key":"a","text":"Cấp toàn quyền admin cho mọi user cho tiện"},{"key":"b","text":"Chỉ cấp đúng quyền tối thiểu cần để hoàn thành công việc"},{"key":"c","text":"Không dùng policy nào cả"},{"key":"d","text":"Chia sẻ chung một IAM user cho cả team"}]'::jsonb, '{b}'),
  ('clf-ts-security-group-basic', (select id from public.topics where slug = 'clf-ts-security-iam'), 'quiz', 'junior', 2, 3, 'Security group trong AWS hoạt động như gì đối với EC2 instance?', 'Security group đóng vai trò virtual firewall ở cấp instance, kiểm soát inbound và outbound traffic bằng rule và có tính stateful. Đây không phải backup, CDN hay công cụ chi phí.', 'single_choice', '[{"key":"a","text":"Một virtual firewall kiểm soát traffic vào/ra instance"},{"key":"b","text":"Một dịch vụ backup dữ liệu"},{"key":"c","text":"Một CDN toàn cầu"},{"key":"d","text":"Một công cụ tính chi phí"}]'::jsonb, '{a}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('clf-billing-pricing', 'Billing, Pricing, and Support', (select id from public.tracks where slug = 'aws-clf'), 3, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-billing-pricing'), 'clf-bp-pricing-models', 'Mô hình định giá', 'junior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-bp-on-demand', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'theory', 'junior', 2, 3, 'Mô hình On-Demand pricing của EC2 hoạt động thế nào?', 'Với On-Demand, bạn trả tiền theo compute capacity dùng (theo giờ hoặc giây) mà không cam kết dài hạn hay trả trước. Phù hợp cho workload ngắn hạn, không dự đoán được, hoặc khi test/dev. Đây là mức giá linh hoạt nhất nhưng đơn giá cao hơn Reserved hay Savings Plans.', null, null, null),
  ('clf-bp-chon-spot-batch', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'quiz', 'junior', 3, 3, 'Workload xử lý batch có thể chịu gián đoạn và cần tiết kiệm chi phí tối đa. Mô hình mua nào phù hợp nhất?', 'Spot Instances dùng dung lượng EC2 dư thừa với giảm giá tới ~90% so với On-Demand, nhưng có thể bị AWS thu hồi. Phù hợp workload chịu gián đoạn như batch, CI/CD, big data. Reserved/On-Demand đắt hơn cho trường hợp này.', 'single_choice', '[{"key":"a","text":"On-Demand Instances"},{"key":"b","text":"Spot Instances"},{"key":"c","text":"Reserved Instances"},{"key":"d","text":"Dedicated Host"}]'::jsonb, '{b}'),
  ('clf-bp-reserved-instances', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'theory', 'junior', 3, 3, 'Reserved Instances (RI) giúp tiết kiệm chi phí bằng cách nào?', 'Reserved Instances cho phép cam kết dùng một loại instance trong 1 hoặc 3 năm để đổi lấy giảm giá tới ~72% so với On-Demand. Phù hợp cho workload ổn định, dự đoán được và chạy liên tục. Có thể trả trước toàn bộ, một phần, hoặc không trả trước (All/Partial/No Upfront).', null, null, null),
  ('clf-bp-savings-plans-chon', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'quiz', 'junior', 3, 3, 'Doanh nghiệp muốn cam kết một mức chi tiêu compute (USD/giờ) trong 1-3 năm để được giảm giá, linh hoạt giữa các loại instance và Region. Lựa chọn nào?', 'Savings Plans cho giảm giá đổi lấy cam kết một mức chi tiêu (USD/hour) trong 1 hoặc 3 năm, linh hoạt hơn RI về instance family, size và Region. Spot dành cho workload gián đoạn; On-Demand không cần cam kết nhưng đắt hơn.', 'single_choice', '[{"key":"a","text":"Spot Instances"},{"key":"b","text":"Savings Plans"},{"key":"c","text":"On-Demand"},{"key":"d","text":"Dedicated Host"}]'::jsonb, '{b}'),
  ('clf-bp-spot-instances', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'theory', 'junior', 3, 3, 'Nêu đặc điểm và rủi ro của Spot Instances.', 'Spot Instances tận dụng dung lượng EC2 dư của AWS với chiết khấu rất lớn (tới ~90%). Rủi ro là AWS có thể thu hồi (interrupt) khi cần dung lượng lại, báo trước khoảng 2 phút. Vì vậy chỉ dùng cho workload chịu gián đoạn, stateless hoặc fault-tolerant, không dùng cho database quan trọng cần chạy liên tục.', null, null, null),
  ('clf-bp-pay-as-you-go-fundamental', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'quiz', 'junior', 1, 3, 'Nguyên tắc định giá cơ bản (pricing fundamental) của AWS là gì?', 'AWS theo mô hình pay-as-you-go: bạn chỉ trả cho tài nguyên thực sự dùng, không cam kết dài hạn bắt buộc. Càng dùng nhiều thường càng rẻ (volume discount) và không phải mua license vĩnh viễn trả trước.', 'single_choice', '[{"key":"a","text":"Trả một khoản cố định hằng năm cho mọi dịch vụ"},{"key":"b","text":"Pay-as-you-go: chỉ trả cho tài nguyên thực dùng"},{"key":"c","text":"Miễn phí toàn bộ dịch vụ"},{"key":"d","text":"Phải mua license vĩnh viễn trước khi dùng"}]'::jsonb, '{b}'),
  ('clf-bp-reserved-vs-savings', (select id from public.topics where slug = 'clf-bp-pricing-models'), 'theory', 'junior', 3, 3, 'So sánh ngắn Reserved Instances và Savings Plans.', 'Cả hai đều đổi cam kết 1-3 năm lấy giảm giá so với On-Demand. Reserved Instances gắn với thuộc tính instance cụ thể (family, Region) nhưng có thể reserve capacity; Savings Plans cam kết theo mức chi tiêu USD/hour và linh hoạt hơn giữa instance family, size, OS, Region. Savings Plans thường đơn giản và linh hoạt hơn để quản lý.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-billing-pricing'), 'clf-bp-support-plans', 'Gói hỗ trợ AWS', 'junior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-bp-support-plans-tong-quan', (select id from public.topics where slug = 'clf-bp-support-plans'), 'theory', 'junior', 2, 3, 'AWS Support có những gói (plan) nào?', 'AWS có 4 gói Support: Basic (miễn phí cho mọi tài khoản), Developer, Business, và Enterprise. Mức càng cao càng có response time nhanh hơn, phạm vi Trusted Advisor đầy đủ hơn, và hỗ trợ 24/7. Enterprise còn có Technical Account Manager (TAM) và Concierge.', null, null, null),
  ('clf-bp-chon-support-enterprise-tam', (select id from public.topics where slug = 'clf-bp-support-plans'), 'quiz', 'junior', 2, 3, 'Doanh nghiệp cần một Technical Account Manager (TAM) chuyên trách và hỗ trợ nhanh nhất. Gói Support nào?', 'Chỉ gói Enterprise Support cung cấp Technical Account Manager (TAM) chuyên trách cùng response time nhanh nhất và hỗ trợ tình huống business-critical trong 15 phút. Basic/Developer/Business không có TAM.', 'single_choice', '[{"key":"a","text":"Basic"},{"key":"b","text":"Developer"},{"key":"c","text":"Business"},{"key":"d","text":"Enterprise"}]'::jsonb, '{d}'),
  ('clf-bp-trusted-advisor', (select id from public.topics where slug = 'clf-bp-support-plans'), 'theory', 'junior', 2, 3, 'AWS Trusted Advisor giúp gì cho khách hàng?', 'Trusted Advisor kiểm tra tài khoản và đưa khuyến nghị theo 5 nhóm: cost optimization, performance, security, fault tolerance, và service limits. Tài khoản Basic/Developer chỉ xem được một số check cơ bản, còn Business/Enterprise mở khóa toàn bộ check. Nó giúp tối ưu chi phí và tăng bảo mật.', null, null, null),
  ('clf-bp-chon-support-developer', (select id from public.topics where slug = 'clf-bp-support-plans'), 'quiz', 'junior', 3, 3, 'Một lập trình viên đang thử nghiệm workload không production, muốn gói trả phí rẻ nhất có hỗ trợ kỹ thuật qua email trong giờ làm việc. Gói nào phù hợp?', 'Developer Support là gói trả phí thấp nhất, cho phép liên hệ Cloud Support Associate qua email trong business hours, phù hợp môi trường test/dev không production. Basic không có hỗ trợ kỹ thuật; Business/Enterprise đắt hơn và cho production.', 'single_choice', '[{"key":"a","text":"Basic"},{"key":"b","text":"Developer"},{"key":"c","text":"Business"},{"key":"d","text":"Enterprise"}]'::jsonb, '{b}'),
  ('clf-bp-support-response-time', (select id from public.topics where slug = 'clf-bp-support-plans'), 'quiz', 'junior', 3, 3, 'Gói Support nào cung cấp hỗ trợ 24/7 qua phone, chat và có cam kết response time cho hệ thống production down?', 'Business và Enterprise Support cung cấp hỗ trợ 24/7 qua phone, chat, email và có cam kết response time cho production system down (Business ~1 giờ, Enterprise nhanh hơn). Developer chỉ email trong giờ làm việc; Basic không có hỗ trợ kỹ thuật.', 'single_choice', '[{"key":"a","text":"Chỉ Basic"},{"key":"b","text":"Developer trở lên"},{"key":"c","text":"Business và Enterprise"},{"key":"d","text":"Không gói nào"}]'::jsonb, '{c}'),
  ('clf-bp-basic-support-free', (select id from public.topics where slug = 'clf-bp-support-plans'), 'theory', 'junior', 1, 3, 'Gói AWS Basic Support miễn phí bao gồm những gì?', 'Basic Support miễn phí cho tất cả tài khoản, gồm: tài liệu, whitepaper, forum cộng đồng, hỗ trợ về billing và account, một số Trusted Advisor check cốt lõi, và AWS Personal Health Dashboard. Nó không bao gồm hỗ trợ kỹ thuật trực tiếp về cấu hình dịch vụ.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'clf-billing-pricing'), 'clf-bp-cost-tools', 'Công cụ quản lý chi phí', 'junior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('clf-bp-cost-explorer', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'theory', 'junior', 2, 3, 'AWS Cost Explorer dùng để làm gì?', 'AWS Cost Explorer là công cụ trực quan hóa, phân tích chi phí và mức sử dụng theo thời gian, cho phép lọc theo service, tag, account. Nó giúp phát hiện xu hướng chi tiêu và dự báo (forecast) chi phí tương lai. Đây là công cụ phân tích lịch sử, khác Budgets dùng để đặt ngưỡng cảnh báo.', null, null, null),
  ('clf-bp-chon-budgets-alert', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'quiz', 'junior', 2, 3, 'Bạn muốn nhận cảnh báo khi chi phí hằng tháng vượt một ngưỡng định trước. Công cụ nào phù hợp?', 'AWS Budgets cho phép đặt ngưỡng chi phí hoặc mức sử dụng và gửi alert (email/SNS) khi vượt hoặc dự báo sẽ vượt. Cost Explorer để phân tích lịch sử; Pricing Calculator để ước tính trước; Trusted Advisor để khuyến nghị.', 'single_choice', '[{"key":"a","text":"AWS Cost Explorer"},{"key":"b","text":"AWS Budgets"},{"key":"c","text":"AWS Pricing Calculator"},{"key":"d","text":"AWS Trusted Advisor"}]'::jsonb, '{b}'),
  ('clf-bp-pricing-calculator', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'theory', 'junior', 2, 3, 'AWS Pricing Calculator dùng khi nào?', 'AWS Pricing Calculator giúp ước tính chi phí (estimate) cho kiến trúc dự kiến trước khi triển khai, bằng cách cấu hình các dịch vụ như EC2, S3, RDS. Kết quả có thể lưu và chia sẻ để lập kế hoạch ngân sách. Đây là công cụ dự toán trước, không phải theo dõi chi phí thực tế.', null, null, null),
  ('clf-bp-chon-tco', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'quiz', 'junior', 2, 3, 'Doanh nghiệp muốn so sánh tổng chi phí sở hữu giữa chạy on-premises và chuyển lên AWS để ra quyết định migration. Khái niệm nào liên quan nhất?', 'Total Cost of Ownership (TCO) phân tích so sánh tổng chi phí on-premises (phần cứng, điện, nhân sự, bảo trì) với chi phí trên AWS để hỗ trợ quyết định migration. Security group, Elastic IP, AZ là khái niệm kỹ thuật, không phải công cụ so sánh chi phí.', 'single_choice', '[{"key":"a","text":"Total Cost of Ownership (TCO)"},{"key":"b","text":"Security group"},{"key":"c","text":"Elastic IP"},{"key":"d","text":"Availability Zone"}]'::jsonb, '{a}'),
  ('clf-bp-organizations-consolidated', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'theory', 'junior', 3, 3, 'Consolidated billing trong AWS Organizations mang lại lợi ích gì?', 'AWS Organizations cho phép gộp nhiều account vào một tổ chức và dùng consolidated billing để nhận một hóa đơn chung. Lợi ích gồm gộp mức sử dụng để hưởng volume discount và chia sẻ Reserved Instances/Savings Plans giữa các account. Nó cũng giúp quản trị tập trung và áp dụng service control policy.', null, null, null),
  ('clf-bp-cost-allocation-tags-quiz', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'quiz', 'junior', 2, 3, 'Công cụ nào giúp phân bổ và theo dõi chi phí AWS theo phòng ban hoặc dự án?', 'Cost allocation tags gắn nhãn (ví dụ Department, Project) lên tài nguyên để nhóm và theo dõi chi phí theo phòng ban/dự án trong Cost Explorer và billing report. ELB, CloudFront, security group không dùng để phân bổ chi phí.', 'single_choice', '[{"key":"a","text":"Cost allocation tags"},{"key":"b","text":"Elastic Load Balancer"},{"key":"c","text":"Amazon CloudFront"},{"key":"d","text":"Security group"}]'::jsonb, '{a}'),
  ('clf-bp-free-tier', (select id from public.topics where slug = 'clf-bp-cost-tools'), 'quiz', 'junior', 1, 3, 'AWS Free Tier cung cấp điều gì cho khách hàng mới?', 'AWS Free Tier cho phép dùng thử nhiều dịch vụ ở mức giới hạn miễn phí theo 3 dạng: 12-month free, always free, và short-term trial. Nó không miễn phí toàn bộ dịch vụ vĩnh viễn; vượt hạn mức sẽ bị tính phí.', 'single_choice', '[{"key":"a","text":"Miễn phí vĩnh viễn mọi dịch vụ AWS"},{"key":"b","text":"Một mức sử dụng giới hạn miễn phí cho nhiều dịch vụ (12 tháng, always free, hoặc trial)"},{"key":"c","text":"Chỉ giảm giá 10% hóa đơn"},{"key":"d","text":"Hỗ trợ Enterprise miễn phí"}]'::jsonb, '{b}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('saa-secure-architectures', 'Design Secure Architectures', (select id from public.tracks where slug = 'aws-saa'), 0, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-secure-architectures'), 'saa-sec-iam', 'IAM & phan quyen', 'mid', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-sec-iam-role-vs-user', (select id from public.topics where slug = 'saa-sec-iam'), 'theory', 'mid', 3, 3, 'Phan biet IAM User va IAM Role. Khi nao nen dung Role thay vi tao user voi access key?', 'IAM User dai dien cho mot nguoi/ung dung co dinh, co credentials dai han (password, access key). IAM Role la danh tinh tam thoi, khong co credentials co dinh; khi assume role ban nhan temporary security credentials tu STS. Nen dung Role cho EC2/Lambda/service khac, cross-account access va workload thay vi nhung access key vi credentials tu xoay vong va khong bi lo.', null, null, null),
  ('saa-sec-iam-policy-evaluation', (select id from public.topics where slug = 'saa-sec-iam'), 'theory', 'mid', 4, 3, 'Giai thich logic danh gia quyen trong IAM khi co nhieu policy: thu tu explicit deny, allow va implicit deny.', 'IAM mac dinh la implicit deny (moi thu bi tu choi tru khi duoc cho phep). Mot explicit Allow trong bat ky policy nao se cap quyen, NHUNG mot explicit Deny luon thang va override moi Allow. Thu tu uu tien: explicit Deny > Allow > implicit Deny. Ap dung cho tong hop identity-based policy, resource-based policy, SCP va permission boundaries.', null, null, null),
  ('saa-sec-iam-instance-profile', (select id from public.topics where slug = 'saa-sec-iam'), 'theory', 'mid', 3, 3, 'Lam sao cap quyen cho ung dung chay tren EC2 goi AWS API ma khong can luu access key tren may?', 'Gan mot IAM Role cho EC2 thong qua instance profile. Ung dung lay temporary credentials tu Instance Metadata Service (IMDS) va cac credentials nay tu dong xoay vong. Cach nay loai bo viec hard-code access key, giam rui ro lo khoa. Nen bat IMDSv2 de chong tan cong SSRF.', null, null, null),
  ('saa-sec-iam-cross-account-sts', (select id from public.topics where slug = 'saa-sec-iam'), 'theory', 'mid', 4, 3, 'Mo ta cach cho phep account B truy cap tai nguyen o account A mot cach an toan (cross-account).', 'O account A tao mot IAM Role voi trust policy cho phep principal cua account B assume role do, va gan permissions can thiet. Account B goi sts:AssumeRole de nhan temporary credentials va thao tac tren tai nguyen account A. Nen them External ID de chong confused deputy khi ben thu ba truy cap.', null, null, null),
  ('saa-sec-iam-quiz-least-privilege', (select id from public.topics where slug = 'saa-sec-iam'), 'quiz', 'mid', 2, 3, 'Ung dung tren EC2 chi can doc object tu mot S3 bucket cu the. Cach cap quyen nao tuan thu least privilege tot nhat?', 'Least privilege nghia la chi cap dung action (s3:GetObject) tren dung resource (ARN cua bucket) qua IAM Role gan cho EC2. Khong dung access key hard-code, khong mo public, khong cap quyen admin thua.', 'single_choice', '[{"key":"a","text":"Gan role AdministratorAccess cho EC2 cho tien."},{"key":"b","text":"Nhung access key cua mot IAM user co quyen S3FullAccess vao code."},{"key":"c","text":"Tao IAM Role voi policy chi cho s3:GetObject tren ARN cua bucket do va gan cho EC2."},{"key":"d","text":"Bat public read cho bucket."}]'::jsonb, '{c}'),
  ('saa-sec-iam-quiz-scp', (select id from public.topics where slug = 'saa-sec-iam'), 'quiz', 'mid', 3, 3, 'Trong AWS Organizations, ban muon dam bao KHONG account thanh vien nao co the tat CloudTrail, ke ca admin cua account do. Dung gi?', 'SCP dat tran quyen toi da cho moi principal trong account thanh vien, ke ca root/admin. Mot explicit Deny trong SCP cho cloudtrail:StopLogging se chan hanh dong bat ke IAM policy cap gi. Day la guardrail cap to chuc.', 'single_choice', '[{"key":"a","text":"IAM policy gan cho tung user."},{"key":"b","text":"Service Control Policy (SCP) voi explicit Deny cho cloudtrail:StopLogging."},{"key":"c","text":"Security Group rule."},{"key":"d","text":"S3 bucket policy."}]'::jsonb, '{b}'),
  ('saa-sec-iam-quiz-federation', (select id from public.topics where slug = 'saa-sec-iam'), 'quiz', 'mid', 3, 3, 'Doanh nghiep co san Active Directory va muon nhan vien dung danh tinh cong ty de dang nhap AWS Console ma khong tao IAM user rieng. Giai phap phu hop?', 'Identity federation (SAML 2.0) hoac AWS IAM Identity Center tich hop AD cho phep SSO bang danh tinh cong ty, cap temporary credentials qua role, khong can tao/duy tri IAM user cho tung nguoi. Giam ganh nang quan tri va tap trung quan ly danh tinh.', 'single_choice', '[{"key":"a","text":"Tao IAM user cho tung nhan vien va dong bo thu cong."},{"key":"b","text":"Identity federation qua SAML 2.0 / IAM Identity Center (SSO) lien ket voi AD."},{"key":"c","text":"Chia se chung mot access key."},{"key":"d","text":"Bat MFA cho root user."}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-secure-architectures'), 'saa-sec-network', 'Network security: SG, NACL & VPC', 'mid', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-sec-sg-vs-nacl', (select id from public.topics where slug = 'saa-sec-network'), 'theory', 'mid', 3, 3, 'So sanh Security Group va Network ACL: stateful/stateless, cap do hoat dong, allow/deny.', 'Security Group hoat dong o cap ENI/instance, la stateful (traffic duoc cho vao thi reply tu dong duoc ra) va chi co rule allow. Network ACL hoat dong o cap subnet, la stateless (phai khai bao ca inbound va outbound), ho tro ca allow va deny theo so thu tu rule. SG la lop bao ve chinh; NACL la lop phu o bien subnet.', null, null, null),
  ('saa-sec-vpc-tiers', (select id from public.topics where slug = 'saa-sec-network'), 'theory', 'mid', 4, 3, 'Thiet ke VPC nhieu tang (web/app/database) an toan nen dat subnet public/private the nao?', 'Dat tang web (ELB, bastion) o public subnet co route ra Internet Gateway; tang app va database o private subnet khong co route truc tiep ra Internet. App/DB ra Internet de update qua NAT Gateway dat o public subnet. Dung Security Group tham chieu lan nhau (SG cua DB chi cho phep tu SG cua app) de phan tang chat che.', null, null, null),
  ('saa-sec-vpc-endpoint', (select id from public.topics where slug = 'saa-sec-network'), 'theory', 'mid', 3, 3, 'Lam sao de EC2 o private subnet truy cap S3 ma traffic khong di ra Internet?', 'Dung VPC Gateway Endpoint cho S3 (va DynamoDB). Endpoint them route vao route table de traffic toi S3 di qua mang noi bo AWS, khong qua Internet Gateway hay NAT. Cach nay an toan hon va khong ton phi NAT; co the kem endpoint policy de gioi han bucket duoc truy cap.', null, null, null),
  ('saa-sec-network-quiz-block-ip', (select id from public.topics where slug = 'saa-sec-network'), 'quiz', 'mid', 3, 3, 'Ban can chan mot dai IP doc hai cu the o cap subnet. Cong cu nao phu hop nhat?', 'Security Group khong ho tro rule deny (chi allow), nen khong the explicit block mot IP. Network ACL ho tro deny rule o cap subnet, phu hop de chan dai IP doc hai. Day la ly do NACL bo sung cho SG.', 'single_choice', '[{"key":"a","text":"Security Group voi rule deny cho dai IP do."},{"key":"b","text":"Network ACL voi rule deny cho dai IP do."},{"key":"c","text":"IAM policy."},{"key":"d","text":"Route table."}]'::jsonb, '{b}'),
  ('saa-sec-network-quiz-db-access', (select id from public.topics where slug = 'saa-sec-network'), 'quiz', 'mid', 2, 3, 'Web server (SG-web) can ket noi toi RDS (SG-db) tren cong 3306. Cau hinh SG-db nao an toan nhat?', 'Tham chieu Security Group (source = SG-web) chi cho phep instance thuoc SG-web ket noi RDS tren 3306, khong phu thuoc IP va tu co gian khi Auto Scaling. An toan hon nhieu so voi mo 0.0.0.0/0 hay ca CIDR.', 'single_choice', '[{"key":"a","text":"Inbound cho 0.0.0.0/0 tren port 3306."},{"key":"b","text":"Inbound cho phep source la SG-web tren port 3306."},{"key":"c","text":"Inbound cho toan bo VPC CIDR tren moi port."},{"key":"d","text":"Mo public IP cho RDS."}]'::jsonb, '{b}'),
  ('saa-sec-network-quiz-nat', (select id from public.topics where slug = 'saa-sec-network'), 'quiz', 'mid', 2, 3, 'Instance o private subnet can tai ban va tu Internet nhung KHONG duoc nhan ket noi den tu Internet. Dung gi?', 'NAT Gateway cho phep instance private khoi tao ket noi ra Internet (outbound) de update, nhung chan ket noi inbound chu dong tu Internet. IGW hoac EIP truc tiep se phoi instance ra ngoai, khong dat yeu cau.', 'single_choice', '[{"key":"a","text":"Internet Gateway gan truc tiep cho instance."},{"key":"b","text":"NAT Gateway o public subnet."},{"key":"c","text":"VPC Peering."},{"key":"d","text":"Elastic IP gan cho instance."}]'::jsonb, '{b}'),
  ('saa-sec-network-quiz-waf', (select id from public.topics where slug = 'saa-sec-network'), 'quiz', 'mid', 3, 3, 'Ban muon bao ve ung dung web sau ALB khoi SQL injection va XSS o tang Layer 7. Dich vu nao?', 'AWS WAF loc HTTP/HTTPS (Layer 7) voi managed rules chong SQLi, XSS va cho phep rule tuy bien; gan duoc voi ALB, CloudFront, API Gateway. Shield chong DDoS (L3/L4), con SG/NACL khong hieu noi dung request tang ung dung.', 'single_choice', '[{"key":"a","text":"AWS Shield Standard."},{"key":"b","text":"AWS WAF gan voi ALB."},{"key":"c","text":"Security Group."},{"key":"d","text":"Network ACL."}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-secure-architectures'), 'saa-sec-encryption', 'Encryption: KMS & secrets', 'mid', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-sec-kms-envelope', (select id from public.topics where slug = 'saa-sec-encryption'), 'theory', 'mid', 4, 3, 'Giai thich envelope encryption trong AWS KMS va vai tro cua data key.', 'KMS dung envelope encryption: mot KMS key (CMK) khong ma hoa truc tiep du lieu lon ma tao ra mot data key. Data key (plaintext) ma hoa du lieu, sau do ban encrypted data key duoc luu cung du lieu con plaintext data key bi xoa khoi bo nho. Khi giai ma, KMS dung KMS key de giai ma data key roi dung no giai ma du lieu, giam tai va tang bao mat.', null, null, null),
  ('saa-sec-kms-key-types', (select id from public.topics where slug = 'saa-sec-encryption'), 'theory', 'mid', 3, 3, 'Phan biet AWS managed key, customer managed key (CMK) va key rotation trong KMS.', 'AWS managed key do dich vu tu tao/quan ly, khong tuy chinh key policy chi tiet. Customer managed key cho phep ban kiem soat key policy, grant, alias va bat automatic rotation (mac dinh hang nam). Customer managed key linh hoat hon cho audit, cross-account va tuan thu; nen dung khi can kiem soat quyen va rotation.', null, null, null),
  ('saa-sec-secrets-manager-vs-ssm', (select id from public.topics where slug = 'saa-sec-encryption'), 'theory', 'mid', 3, 3, 'Khi nao dung AWS Secrets Manager thay vi SSM Parameter Store de luu credentials?', 'Secrets Manager ho tro automatic rotation tich hop (vi du xoay password RDS qua Lambda) va tinh phi theo secret. SSM Parameter Store (SecureString) re/mien phi o standard tier, phu hop config va secret don gian nhung khong tu rotation goc. Chon Secrets Manager khi can rotation tu dong; chon Parameter Store cho config va tiet kiem chi phi.', null, null, null),
  ('saa-sec-encryption-quiz-s3-sse-kms', (select id from public.topics where slug = 'saa-sec-encryption'), 'quiz', 'mid', 3, 3, 'Yeu cau: ma hoa object S3 at-rest, co audit log moi lan khoa duoc dung, va kiem soat quyen dung khoa. Chon phuong an nao?', 'SSE-KMS voi customer managed key cho phep kiem soat key policy va ghi moi lan dung khoa vao CloudTrail (audit). SSE-S3 ma hoa nhung khong cho audit/kiem soat khoa chi tiet. Day la lua chon can bang bao mat va tuan thu.', 'single_choice', '[{"key":"a","text":"SSE-S3 (khoa do S3 quan ly)."},{"key":"b","text":"SSE-KMS voi customer managed key."},{"key":"c","text":"Khong ma hoa, chi dung bucket policy."},{"key":"d","text":"Client-side encryption voi khoa luu trong code."}]'::jsonb, '{b}'),
  ('saa-sec-encryption-quiz-in-transit', (select id from public.topics where slug = 'saa-sec-encryption'), 'quiz', 'mid', 2, 3, 'Cach nao dam bao du lieu duoc ma hoa in-transit giua client va ALB?', 'Ma hoa in-transit dung TLS/HTTPS. Cau hinh HTTPS listener tren ALB voi chung chi tu AWS Certificate Manager (ACM) ma hoa traffic giua client va ALB. SSE-KMS va EBS encryption la at-rest, khong lien quan in-transit.', 'single_choice', '[{"key":"a","text":"Bat SSE-KMS tren S3."},{"key":"b","text":"Cau hinh HTTPS listener voi ACM certificate tren ALB."},{"key":"c","text":"Dung NACL chan port 80."},{"key":"d","text":"Bat EBS encryption."}]'::jsonb, '{b}'),
  ('saa-sec-encryption-quiz-rotation', (select id from public.topics where slug = 'saa-sec-encryption'), 'quiz', 'mid', 3, 3, 'Password cua RDS can duoc tu dong xoay vong dinh ky ma khong sua code ung dung. Dich vu nao?', 'Secrets Manager ho tro automatic rotation tich hop cho RDS qua Lambda function, ung dung chi doc secret hien tai nen khong can doi code. KMS key rotation xoay khoa ma hoa chu khong phai credential; Parameter Store standard khong co rotation goc.', 'single_choice', '[{"key":"a","text":"SSM Parameter Store standard tier."},{"key":"b","text":"AWS Secrets Manager voi rotation bat cho RDS."},{"key":"c","text":"IAM access key rotation."},{"key":"d","text":"KMS key rotation."}]'::jsonb, '{b}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('saa-resilient-architectures', 'Design Resilient Architectures', (select id from public.tracks where slug = 'aws-saa'), 1, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-resilient-architectures'), 'saa-res-ha', 'High Availability: Multi-AZ, ELB, Auto Scaling', 'mid', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-res-multi-az-vs-multi-region', (select id from public.topics where slug = 'saa-res-ha'), 'theory', 'mid', 3, 3, 'Phan biet Multi-AZ va Multi-Region ve muc tieu availability va do tre.', 'Multi-AZ trien khai tai nguyen tren nhieu Availability Zone trong cung mot Region de chiu loi o muc data center, voi do tre thap (mang noi Region). Multi-Region trai tren nhieu Region de chiu loi cap Region va phuc vu nguoi dung toan cau, nhung phuc tap va chi phi cao hon. Da so kien truc HA bat dau bang Multi-AZ; Multi-Region dung cho DR/do san sang cuc cao.', null, null, null),
  ('saa-res-rds-multi-az', (select id from public.topics where slug = 'saa-res-ha'), 'theory', 'mid', 3, 3, 'RDS Multi-AZ hoat dong the nao khi AZ chinh gap su co? Standby co phuc vu read khong?', 'RDS Multi-AZ duy tri mot standby replica dong bo (synchronous) o AZ khac. Khi primary loi, RDS tu dong failover sang standby bang cach tro DNS endpoint sang instance moi, thuong trong 1-2 phut. Standby KHONG phuc vu read/write khi dang standby; muon scale read phai dung Read Replica (asynchronous).', null, null, null),
  ('saa-res-asg-health', (select id from public.topics where slug = 'saa-res-ha'), 'theory', 'mid', 3, 3, 'Auto Scaling Group dung health check the nao de tu phuc hoi, va khac gi khi bat ELB health check?', 'ASG mac dinh dung EC2 status check; neu instance unhealthy, ASG terminate va launch instance moi de giu desired capacity (self-healing). Bat ELB health check giup ASG coi instance la unhealthy khi ung dung (target) fail health check cua load balancer, khong chi khi may chet. Ket hop ASG + ELB cho HA va tu phuc hoi cap ung dung.', null, null, null),
  ('saa-res-ha-quiz-alb-multiaz', (select id from public.topics where slug = 'saa-res-ha'), 'quiz', 'mid', 2, 3, 'Kien truc web can chiu duoc loi cua mot Availability Zone. Cau hinh nao dung?', 'De chiu loi AZ, ALB phai bat nhieu AZ va Auto Scaling Group phan bo instance qua tu 2 AZ tro len. Khi mot AZ hong, ALB dinh tuyen sang AZ con lai va ASG thay the instance. Single AZ hay single EC2 la single point of failure.', 'single_choice', '[{"key":"a","text":"Chay tat ca EC2 trong mot AZ duy nhat sau ALB."},{"key":"b","text":"ALB trai tren nhieu AZ, Auto Scaling Group dat instance o tu 2 AZ tro len."},{"key":"c","text":"Mot EC2 lon voi Elastic IP."},{"key":"d","text":"Dat tat ca trong mot subnet."}]'::jsonb, '{b}'),
  ('saa-res-ha-quiz-elb-type', (select id from public.topics where slug = 'saa-res-ha'), 'quiz', 'mid', 2, 3, 'Ung dung can dinh tuyen HTTP theo path (/api, /images) va ho tro WebSocket. Loai load balancer nao?', 'Application Load Balancer (Layer 7) ho tro path-based/host-based routing va WebSocket, phu hop HTTP/HTTPS. NLB la Layer 4 cho throughput/do tre cuc thap, GWLB cho appliance mang, CLB da loi thoi.', 'single_choice', '[{"key":"a","text":"Classic Load Balancer."},{"key":"b","text":"Network Load Balancer."},{"key":"c","text":"Application Load Balancer."},{"key":"d","text":"Gateway Load Balancer."}]'::jsonb, '{c}'),
  ('saa-res-ha-quiz-scaling-policy', (select id from public.topics where slug = 'saa-res-ha'), 'quiz', 'mid', 3, 3, 'Ban muon ASG tu giu CPU trung binh quanh 50% khi tai thay doi. Loai scaling policy nao phu hop nhat?', 'Target tracking scaling tu dieu chinh so instance de giu metric quanh gia tri muc tieu (vi du 50% CPU), don gian va phan ung theo tai. Scheduled scaling chi hop khi biet truoc lich tai; manual khong tu dong.', 'single_choice', '[{"key":"a","text":"Manual scaling."},{"key":"b","text":"Target tracking scaling (target = 50% CPU)."},{"key":"c","text":"Scheduled scaling co dinh."},{"key":"d","text":"Khong dung scaling."}]'::jsonb, '{b}'),
  ('saa-res-ha-quiz-stateless', (select id from public.topics where slug = 'saa-res-ha'), 'quiz', 'mid', 3, 3, 'De ASG them/bot instance ma khong mat session nguoi dung, nen lam gi voi session state?', 'Thiet ke instance stateless bang cach dua session ra store dung chung nhu ElastiCache (Redis) hoac DynamoDB. Khi do ASG co the thay the/scale instance tu do ma khong mat session; luu session cuc bo se mat khi instance bi terminate.', 'single_choice', '[{"key":"a","text":"Luu session tren o dia cuc bo cua moi EC2."},{"key":"b","text":"Luu session ngoai, vi du ElastiCache/DynamoDB, de instance stateless."},{"key":"c","text":"Tat Auto Scaling."},{"key":"d","text":"Dung Elastic IP cho moi instance."}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-resilient-architectures'), 'saa-res-decoupling', 'Decoupling: SQS & SNS', 'mid', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-res-sqs-decouple', (select id from public.topics where slug = 'saa-res-decoupling'), 'theory', 'mid', 3, 3, 'Vi sao dung SQS giua producer va consumer giup kien truc resilient hon?', 'SQS la hang doi luu message ben vung, tach roi (decouple) producer va consumer de chung scale va fail doc lap. Khi consumer cham hoac chet, message van nam trong queue (retention toi da 14 ngay) va duoc xu ly khi consumer hoi phuc, giup hap thu spike tai va tranh mat du lieu. Ket hop ASG scale consumer theo do sau queue.', null, null, null),
  ('saa-res-sqs-standard-vs-fifo', (select id from public.topics where slug = 'saa-res-decoupling'), 'theory', 'mid', 3, 3, 'So sanh SQS Standard va FIFO ve thu tu va do trung lap.', 'SQS Standard cho throughput gan nhu khong gioi han nhung chi dam bao at-least-once va best-effort ordering (co the trung va sai thu tu). SQS FIFO dam bao exactly-once processing va giu dung thu tu trong message group, nhung throughput gioi han. Chon FIFO khi thu tu/khong trung la bat buoc, vi du giao dich.', null, null, null),
  ('saa-res-sns-fanout', (select id from public.topics where slug = 'saa-res-decoupling'), 'theory', 'mid', 3, 3, 'Mo hinh fan-out voi SNS + SQS hoat dong the nao va loi ich gi?', 'SNS la pub/sub: publisher gui message toi mot topic, SNS day ban sao toi nhieu subscriber (nhieu SQS queue, Lambda, HTTP). Mo hinh fan-out cho phep nhieu he thong xu ly song song cung su kien, moi queue doc lap va ben vung. Loi ich: decouple, mo rong them consumer ma khong sua publisher, tang kha nang chiu loi.', null, null, null),
  ('saa-res-decoupling-quiz-spike', (select id from public.topics where slug = 'saa-res-decoupling'), 'quiz', 'mid', 2, 3, 'Backend xu ly don hang bi qua tai khi co dot khuyen mai, request den don dap gay mat don. Giai phap decouple nao phu hop?', 'SQS dung giua hap thu spike: frontend day don vao queue nhanh, backend consume theo kha nang, khong mat don khi tai cao. Day la buffering + decoupling kinh dien, ket hop ASG scale consumer theo do sau queue.', 'single_choice', '[{"key":"a","text":"Tang timeout cua web server."},{"key":"b","text":"Dat SQS queue giua frontend va backend, backend consume theo toc do xu ly."},{"key":"c","text":"Chuyen sang mot EC2 lon hon duy nhat."},{"key":"d","text":"Bo qua bot request."}]'::jsonb, '{b}'),
  ('saa-res-decoupling-quiz-dlq', (select id from public.topics where slug = 'saa-res-decoupling'), 'quiz', 'mid', 3, 3, 'Mot so message trong SQS lien tuc xu ly that bai va bi retry vo han, lam nghen queue. Cau hinh nao giup co lap chung?', 'Dead-Letter Queue nhan cac message vuot qua maxReceiveCount (so lan nhan that bai), tach chung khoi queue chinh de phan tich rieng va tranh nghen. Day la cach xu ly poison-pill message chuan.', 'single_choice', '[{"key":"a","text":"Tang visibility timeout len toi da."},{"key":"b","text":"Cau hinh Dead-Letter Queue (DLQ) voi maxReceiveCount."},{"key":"c","text":"Xoa toan bo queue."},{"key":"d","text":"Chuyen sang SNS."}]'::jsonb, '{b}'),
  ('saa-res-decoupling-quiz-fanout', (select id from public.topics where slug = 'saa-res-decoupling'), 'quiz', 'mid', 3, 3, 'Mot su kien ''don hang moi'' can duoc xu ly dong thoi boi he thong kho, thanh toan va email, moi he thong doc lap va ben vung. Kien truc nao?', 'SNS fan-out gui ban sao su kien toi nhieu SQS queue, moi he thong (kho/thanh toan/email) tieu thu doc lap, ben vung va co the retry rieng. Goi HTTP dong bo tao coupling va de mat du lieu khi mot service loi; mot queue chung khien ba he thong tranh message.', 'single_choice', '[{"key":"a","text":"Goi tuan tu tung service bang HTTP dong bo."},{"key":"b","text":"SNS topic fan-out toi nhieu SQS queue, moi he thong mot queue."},{"key":"c","text":"Mot SQS queue duy nhat cho ca ba."},{"key":"d","text":"Ghi vao mot file log chung."}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-resilient-architectures'), 'saa-res-dr', 'Backup & DR: RTO/RPO, Route 53', 'mid', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-res-rto-rpo', (select id from public.topics where slug = 'saa-res-dr'), 'theory', 'mid', 3, 3, 'Dinh nghia RTO va RPO, va chung anh huong the nao toi lua chon chien luoc DR?', 'RTO (Recovery Time Objective) la thoi gian toi da chap nhan duoc de khoi phuc dich vu sau su co. RPO (Recovery Point Objective) la luong du lieu toi da (theo thoi gian) chap nhan mat, quyet dinh tan suat backup/replication. RTO/RPO cang nho thi chien luoc cang dat: tu Backup & Restore (lon) den Pilot Light, Warm Standby, Multi-Site active-active (nho nhat).', null, null, null),
  ('saa-res-dr-strategies', (select id from public.topics where slug = 'saa-res-dr'), 'theory', 'mid', 4, 3, 'Liet ke 4 chien luoc DR cua AWS theo thu tu RTO/RPO giam dan va chi phi tang dan.', 'Bon chien luoc: (1) Backup & Restore, re nhat, RTO/RPO cao (gio). (2) Pilot Light, chay toi thieu core (vi du database replicate), khoi dong phan con lai khi can. (3) Warm Standby, ban thu nho luon chay, scale up khi failover. (4) Multi-Site active-active, chay day du o nhieu Region, RTO/RPO gan 0 nhung dat nhat.', null, null, null),
  ('saa-res-route53-failover', (select id from public.topics where slug = 'saa-res-dr'), 'theory', 'mid', 3, 3, 'Route 53 ho tro DR/HA qua routing policy nao, va health check dung de lam gi?', 'Route 53 Failover routing policy tro traffic sang endpoint du phong khi endpoint chinh unhealthy, dua tren health check dinh ky. Ngoai ra co latency-based, geolocation, weighted, multivalue de phan phoi traffic. Health check giam sat endpoint va tu dong loai bo endpoint hong khoi phan hoi DNS, giup failover tu dong cap Region.', null, null, null),
  ('saa-res-backup-aurora-s3', (select id from public.topics where slug = 'saa-res-dr'), 'theory', 'mid', 4, 3, 'Cac co che backup nao giup dat RPO thap cho du lieu tren RDS/Aurora va S3?', 'RDS/Aurora ho tro automated backup va point-in-time recovery (PITR) khoi phuc ve thoi diem bat ky trong retention (RPO tinh bang phut). Aurora con replicate storage 6 ban qua 3 AZ. S3 dung versioning de chong ghi de/xoa nham va Cross-Region Replication (CRR) de sao chep qua Region cho DR. Ket hop giup RPO thap va ben vung cao.', null, null, null),
  ('saa-res-dr-quiz-cheapest', (select id from public.topics where slug = 'saa-res-dr'), 'quiz', 'mid', 2, 3, 'Ung dung noi bo it quan trong, chap nhan RTO vai gio va RPO 1 ngay. Chien luoc DR tiet kiem nhat?', 'Voi RTO/RPO noi long (gio/ngay), Backup & Restore la re nhat: chi luu backup (vi du snapshot/S3) va khoi phuc khi co su co, khong phai duy tri ha tang chay song song. Cac chien luoc kia dat hon va chi can khi RTO/RPO nho.', 'single_choice', '[{"key":"a","text":"Multi-Site active-active."},{"key":"b","text":"Warm Standby."},{"key":"c","text":"Backup & Restore (backup dinh ky, khoi phuc khi can)."},{"key":"d","text":"Pilot Light."}]'::jsonb, '{c}'),
  ('saa-res-dr-quiz-s3-durability', (select id from public.topics where slug = 'saa-res-dr'), 'quiz', 'mid', 2, 3, 'Ban can luu backup voi do ben cao va tu dong chiu duoc loi cua mot Availability Zone. Lua chon nao?', 'S3 Standard luu du lieu du thua qua toi thieu 3 AZ voi do ben 99.999999999% (11 so 9), tu chiu loi AZ. EBS va instance store gan voi mot AZ; S3 One Zone-IA chi o mot AZ nen khong chiu duoc loi AZ.', 'single_choice', '[{"key":"a","text":"Luu tren mot EBS volume."},{"key":"b","text":"S3 Standard (du lieu tu replicate qua tu 3 AZ tro len, 11 so 9 durability)."},{"key":"c","text":"Instance store cua EC2."},{"key":"d","text":"S3 One Zone-IA."}]'::jsonb, '{b}'),
  ('saa-res-dr-quiz-route53', (select id from public.topics where slug = 'saa-res-dr'), 'quiz', 'mid', 3, 3, 'Site chinh o Region A. Khi A down, traffic phai tu chuyen sang site du phong o Region B. Cau hinh DNS nao?', 'Route 53 Failover routing voi health check giam sat endpoint chinh (Region A); khi health check fail, Route 53 tu tra ve endpoint du phong (Region B). Day la co che DNS failover tu dong cap Region cho DR.', 'single_choice', '[{"key":"a","text":"Weighted routing 50/50."},{"key":"b","text":"Failover routing policy voi health check tren endpoint chinh."},{"key":"c","text":"Simple routing toi Region A."},{"key":"d","text":"Geolocation routing."}]'::jsonb, '{b}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('saa-high-performing', 'Design High-Performing Architectures', (select id from public.tracks where slug = 'aws-saa'), 2, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-high-performing'), 'saa-perf-caching', 'Caching & CDN', 'mid', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-perf-cloudfront-la-gi', (select id from public.topics where slug = 'saa-perf-caching'), 'theory', 'mid', 2, 3, 'Amazon CloudFront là gì và nó cải thiện performance như thế nào?', 'CloudFront là Content Delivery Network (CDN) của AWS, cache nội dung tại các edge location gần user trên toàn cầu. Khi user request, nội dung được phục vụ từ edge gần nhất giúp giảm latency và giảm tải cho origin (S3, ALB, EC2). Phù hợp cho static content, video streaming và cả dynamic content thông qua các cache behavior.', null, null, null),
  ('saa-perf-elasticache-redis-memcached', (select id from public.topics where slug = 'saa-perf-caching'), 'theory', 'mid', 3, 3, 'So sánh Redis và Memcached trong Amazon ElastiCache.', 'Redis hỗ trợ persistence, replication (read replica), Multi-AZ failover và các data structure phức tạp (sorted set, list), phù hợp khi cần high availability và tính năng phong phú. Memcached đơn giản, multi-threaded, dễ scale ngang (sharding) nhưng không có persistence hay replication. Chọn Redis khi cần durability/HA, chọn Memcached khi chỉ cần cache đơn giản, tốc độ cao.', null, null, null),
  ('saa-perf-cloudfront-cache-behavior', (select id from public.topics where slug = 'saa-perf-caching'), 'theory', 'mid', 3, 3, 'Cache behavior và TTL trong CloudFront dùng để làm gì?', 'Cache behavior định nghĩa cách CloudFront xử lý request theo path pattern (ví dụ /images/* dùng cache lâu, /api/* không cache). TTL (Time To Live) quyết định thời gian một object được giữ trong cache trước khi CloudFront kiểm tra lại với origin. Điều chỉnh TTL và cache policy giúp cân bằng giữa độ tươi của dữ liệu và hiệu quả caching.', null, null, null),
  ('saa-perf-cloudfront-static-content', (select id from public.topics where slug = 'saa-perf-caching'), 'quiz', 'mid', 2, 3, 'Một website tĩnh lưu trên S3 phục vụ user toàn cầu bị latency cao ở các vùng xa. Giải pháp tối ưu performance là gì?', 'CloudFront cache nội dung tại edge location gần user, giảm latency toàn cầu và giảm tải cho S3 origin.', 'single_choice', '[{"key":"a","text":"Bật S3 Transfer Acceleration cho bucket"},{"key":"b","text":"Đặt CloudFront distribution trước S3 bucket"},{"key":"c","text":"Nhân bản bucket sang mọi Region và tự route"},{"key":"d","text":"Tăng kích thước instance của web server"}]'::jsonb, '{b}'),
  ('saa-perf-db-read-cache', (select id from public.topics where slug = 'saa-perf-caching'), 'quiz', 'mid', 3, 3, 'Ứng dụng đọc lặp lại cùng dữ liệu từ RDS gây tải cao. Cách giảm tải đọc và tăng tốc hiệu quả nhất?', 'ElastiCache lưu kết quả truy vấn thường dùng trong bộ nhớ, giảm số lần truy vấn tới database và trả về nhanh hơn.', 'single_choice', '[{"key":"a","text":"Đặt ElastiCache làm lớp cache trước RDS"},{"key":"b","text":"Chuyển RDS sang instance lớn hơn liên tục"},{"key":"c","text":"Bật Multi-AZ cho RDS"},{"key":"d","text":"Dùng CloudFront cache trực tiếp query DB"}]'::jsonb, '{a}'),
  ('saa-perf-session-store', (select id from public.topics where slug = 'saa-perf-caching'), 'quiz', 'mid', 3, 3, 'Ứng dụng web chạy trên nhiều EC2 sau ALB cần lưu session dùng chung để hỗ trợ stateless scaling. Lựa chọn nào phù hợp?', 'ElastiCache for Redis là in-memory store dùng chung, cho phép mọi instance đọc/ghi session nhanh, hỗ trợ ứng dụng stateless.', 'single_choice', '[{"key":"a","text":"Lưu session trong bộ nhớ cục bộ từng EC2"},{"key":"b","text":"Lưu session vào EBS gắn từng instance"},{"key":"c","text":"Lưu session tập trung trong ElastiCache for Redis"},{"key":"d","text":"Bật sticky session và không cần store dùng chung"}]'::jsonb, '{c}'),
  ('saa-perf-elasticache-usecase', (select id from public.topics where slug = 'saa-perf-caching'), 'quiz', 'mid', 2, 3, 'Trường hợp nào phù hợp nhất để dùng ElastiCache?', 'ElastiCache tối ưu cho dữ liệu đọc nhiều, cần độ trễ sub-millisecond như leaderboard, session, cache kết quả query.', 'single_choice', '[{"key":"a","text":"Lưu trữ dài hạn file backup dung lượng lớn"},{"key":"b","text":"Cache dữ liệu đọc nhiều cần latency sub-millisecond"},{"key":"c","text":"Xử lý giao dịch ACID nhiều bảng phức tạp"},{"key":"d","text":"Phân phối video tĩnh cho user toàn cầu"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-high-performing'), 'saa-perf-compute-storage', 'Compute & Storage Performance', 'mid', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-perf-ebs-volume-types', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'theory', 'mid', 3, 3, 'Kể tên các loại EBS volume chính và use case của chúng.', 'gp3/gp2 (General Purpose SSD) cân bằng giá và hiệu năng cho hầu hết workload. io2/io1 (Provisioned IOPS SSD) cho ứng dụng cần IOPS cao và độ trễ thấp ổn định như database lớn. st1 (Throughput Optimized HDD) cho workload throughput cao tuần tự như big data, sc1 (Cold HDD) cho dữ liệu ít truy cập, chi phí thấp nhất.', null, null, null),
  ('saa-perf-instance-store', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'theory', 'mid', 3, 3, 'Instance store khác EBS như thế nào về performance và độ bền?', 'Instance store là ổ đĩa vật lý gắn trực tiếp vào host, cho IOPS và throughput rất cao với latency cực thấp, nhưng dữ liệu là ephemeral (mất khi instance stop/terminate). EBS là network-attached, dữ liệu bền vững độc lập với vòng đời instance. Dùng instance store cho cache/scratch data cần tốc độ, dùng EBS cho dữ liệu cần lưu trữ lâu dài.', null, null, null),
  ('saa-perf-efs-fsx', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'theory', 'mid', 3, 3, 'Khi nào chọn Amazon EFS và khi nào chọn Amazon FSx?', 'EFS là file system NFS được quản lý, tự scale, cho phép nhiều EC2 Linux mount đồng thời, phù hợp shared storage cho workload Linux. FSx cung cấp file system chuyên biệt: FSx for Windows File Server (SMB cho Windows) và FSx for Lustre (HPC, hiệu năng cực cao). Chọn EFS cho Linux shared storage phổ thông, FSx khi cần Windows/SMB hoặc compute hiệu năng cao.', null, null, null),
  ('saa-perf-ebs-high-iops', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'quiz', 'mid', 3, 3, 'Database quan trọng cần IOPS rất cao và độ trễ thấp ổn định. Loại EBS volume nào phù hợp nhất?', 'io2/io1 Provisioned IOPS SSD cho phép cấu hình IOPS cao và ổn định, phù hợp database yêu cầu hiệu năng khắt khe.', 'single_choice', '[{"key":"a","text":"sc1 (Cold HDD)"},{"key":"b","text":"st1 (Throughput Optimized HDD)"},{"key":"c","text":"io2 (Provisioned IOPS SSD)"},{"key":"d","text":"Magnetic (standard) volume"}]'::jsonb, '{c}'),
  ('saa-perf-s3-request-rate', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'quiz', 'mid', 3, 3, 'Ứng dụng cần request rate rất cao trên một S3 bucket. Cách nào giúp mở rộng throughput hiệu quả?', 'S3 tự scale theo prefix; phân bổ object trên nhiều prefix cho phép đạt hàng nghìn request/giây song song trên mỗi prefix.', 'single_choice', '[{"key":"a","text":"Phân bố key object trên nhiều prefix khác nhau"},{"key":"b","text":"Dồn tất cả object vào một prefix duy nhất"},{"key":"c","text":"Bật versioning để tăng throughput"},{"key":"d","text":"Chuyển bucket sang một Region gần hơn"}]'::jsonb, '{a}'),
  ('saa-perf-placement-group', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'quiz', 'mid', 3, 3, 'Cluster HPC cần băng thông network cao và latency thấp giữa các EC2 trong cùng AZ. Nên dùng gì?', 'Cluster placement group đặt các instance gần nhau trong cùng AZ, cho network throughput cao và latency thấp giữa các node.', 'single_choice', '[{"key":"a","text":"Spread placement group trên nhiều AZ"},{"key":"b","text":"Cluster placement group trong một AZ"},{"key":"c","text":"Auto Scaling group trải đều mọi AZ"},{"key":"d","text":"Partition placement group cho HDFS"}]'::jsonb, '{b}'),
  ('saa-perf-s3-transfer-acceleration', (select id from public.topics where slug = 'saa-perf-compute-storage'), 'quiz', 'mid', 2, 3, 'User ở xa cần upload file lớn lên S3 nhanh hơn qua Internet công cộng. Tính năng nào giúp tăng tốc?', 'S3 Transfer Acceleration định tuyến upload qua edge location của CloudFront rồi tới bucket qua mạng backbone AWS, tăng tốc truyền dữ liệu đường dài.', 'single_choice', '[{"key":"a","text":"S3 Transfer Acceleration"},{"key":"b","text":"S3 Cross-Region Replication"},{"key":"c","text":"S3 Intelligent-Tiering"},{"key":"d","text":"S3 Object Lock"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-high-performing'), 'saa-perf-database-scaling', 'Database Performance & Scaling', 'mid', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-perf-rds-read-replica', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'theory', 'mid', 3, 3, 'RDS Read Replica dùng để làm gì và khác Multi-AZ như thế nào?', 'Read Replica tạo bản sao read-only đồng bộ bất đồng bộ (asynchronous) để offload truy vấn đọc, giúp scale read-heavy workload; có thể tạo tối đa nhiều replica và cross-Region. Multi-AZ là bản standby đồng bộ(synchronous) chỉ dùng cho high availability/failover, không phục vụ đọc. Read Replica tối ưu performance đọc, Multi-AZ tối ưu availability.', null, null, null),
  ('saa-perf-dynamodb-dax', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'theory', 'mid', 3, 3, 'DynamoDB Accelerator (DAX) là gì?', 'DAX là in-memory cache được quản lý dành riêng cho DynamoDB, giảm thời gian phản hồi đọc từ mili-giây xuống micro-giây cho read-heavy workload. Nó tương thích API DynamoDB nên ứng dụng gần như không cần đổi code. Phù hợp khi cần tốc độ đọc cực cao và giảm chi phí read capacity trên bảng.', null, null, null),
  ('saa-perf-aurora-benefits', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'theory', 'mid', 3, 3, 'Amazon Aurora mang lại lợi ích performance gì so với RDS MySQL/PostgreSQL truyền thống?', 'Aurora là database engine tương thích MySQL/PostgreSQL nhưng nhanh hơn nhiều lần nhờ kiến trúc storage phân tán tự nhân 6 bản trên 3 AZ. Nó hỗ trợ tới 15 read replica với độ trễ replication thấp, tự động scale storage tới 128 TB và failover nhanh. Phù hợp cho ứng dụng cần hiệu năng cao và độ sẵn sàng lớn.', null, null, null),
  ('saa-perf-scale-reads', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'quiz', 'mid', 3, 3, 'Ứng dụng đọc nhiều gấp bội ghi trên RDS gây nghẽn. Cách scale phần đọc phù hợp nhất là gì?', 'Read Replica offload truy vấn đọc sang các bản sao read-only, cho phép scale ngang phần đọc mà không ảnh hưởng instance ghi chính.', 'single_choice', '[{"key":"a","text":"Bật Multi-AZ để standby phục vụ đọc"},{"key":"b","text":"Thêm RDS Read Replica cho truy vấn đọc"},{"key":"c","text":"Chuyển sang một instance ghi lớn hơn duy nhất"},{"key":"d","text":"Tắt backup để tăng tài nguyên đọc"}]'::jsonb, '{b}'),
  ('saa-perf-dynamodb-scaling', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'quiz', 'mid', 3, 3, 'Bảng DynamoDB có lưu lượng biến động khó dự đoán, đôi khi tăng đột biến. Chế độ capacity nào phù hợp để duy trì performance?', 'On-demand capacity tự động scale theo lưu lượng tức thời, phù hợp workload không dự đoán được mà không cần cấu hình capacity thủ công.', 'single_choice', '[{"key":"a","text":"Provisioned capacity cố định thấp"},{"key":"b","text":"On-demand capacity mode"},{"key":"c","text":"Tắt auto scaling hoàn toàn"},{"key":"d","text":"Chuyển toàn bộ dữ liệu sang RDS"}]'::jsonb, '{b}'),
  ('saa-perf-auto-scaling-group', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'quiz', 'mid', 2, 3, 'Tầng web cần tự động thêm/bớt EC2 theo tải để giữ hiệu năng ổn định. Dùng gì?', 'Auto Scaling Group với scaling policy (ví dụ target tracking theo CPU) tự thêm/bớt instance theo tải, duy trì hiệu năng và tối ưu tài nguyên.', 'single_choice', '[{"key":"a","text":"Một EC2 instance thật lớn cố định"},{"key":"b","text":"Auto Scaling Group với target tracking policy"},{"key":"c","text":"Chỉ dùng CloudFront cho tầng web"},{"key":"d","text":"Tăng kích thước EBS volume định kỳ"}]'::jsonb, '{b}'),
  ('saa-perf-elb-type', (select id from public.topics where slug = 'saa-perf-database-scaling'), 'quiz', 'mid', 2, 3, 'Ứng dụng HTTP/HTTPS cần cân bằng tải với routing theo path và host header. Loại load balancer nào phù hợp?', 'Application Load Balancer (ALB) hoạt động ở layer 7, hỗ trợ path-based và host-based routing cho HTTP/HTTPS.', 'single_choice', '[{"key":"a","text":"Network Load Balancer (NLB)"},{"key":"b","text":"Gateway Load Balancer (GWLB)"},{"key":"c","text":"Application Load Balancer (ALB)"},{"key":"d","text":"Classic Load Balancer chỉ TCP"}]'::jsonb, '{c}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('saa-cost-optimized', 'Design Cost-Optimized Architectures', (select id from public.tracks where slug = 'aws-saa'), 3, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-cost-optimized'), 'saa-cost-compute-pricing', 'Compute Pricing Models', 'mid', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-cost-ec2-pricing-models', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'theory', 'mid', 3, 3, 'Tổng quan các mô hình định giá EC2 để tối ưu chi phí.', 'On-Demand trả theo giờ/giây, linh hoạt nhưng đắt nhất, hợp workload ngắn hạn/không dự đoán. Reserved Instances và Savings Plans cam kết 1-3 năm để giảm tới ~72% cho workload ổn định. Spot Instances rẻ nhất (giảm tới ~90%) nhưng có thể bị thu hồi, hợp workload chịu lỗi. Dedicated Hosts cho yêu cầu compliance/licensing riêng.', null, null, null),
  ('saa-cost-spot-instances', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'theory', 'mid', 3, 3, 'Spot Instances là gì và khi nào nên dùng?', 'Spot Instances dùng capacity dư thừa của AWS với mức giảm giá lên tới ~90% so với On-Demand, nhưng AWS có thể thu hồi (interruption) khi cần lại capacity, báo trước 2 phút. Phù hợp cho workload chịu lỗi và có thể dừng/khởi động lại như batch processing, CI/CD, big data, rendering. Không nên dùng cho workload trạng thái quan trọng không thể gián đoạn.', null, null, null),
  ('saa-cost-savings-plans', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'theory', 'mid', 3, 3, 'Savings Plans khác Reserved Instances như thế nào?', 'Savings Plans cam kết một mức chi tiêu ($/giờ) trong 1 hoặc 3 năm để đổi lấy giá giảm. Compute Savings Plans linh hoạt áp dụng cho EC2, Fargate, Lambda ở mọi Region/family; EC2 Instance Savings Plans giảm sâu hơn nhưng gắn với family trong một Region. So với Reserved Instances, Savings Plans thường linh hoạt hơn về loại instance và dịch vụ.', null, null, null),
  ('saa-cost-steady-workload', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'quiz', 'mid', 2, 3, 'Một workload production chạy 24/7 ổn định suốt vài năm. Mô hình định giá nào tối ưu chi phí nhất?', 'Reserved Instances hoặc Savings Plans cam kết 1-3 năm cho workload ổn định, giảm tới ~72% so với On-Demand.', 'single_choice', '[{"key":"a","text":"On-Demand cho toàn bộ thời gian"},{"key":"b","text":"Spot Instances cho production 24/7"},{"key":"c","text":"Reserved Instances / Savings Plans 3 năm"},{"key":"d","text":"Dedicated Hosts trả theo giờ"}]'::jsonb, '{c}'),
  ('saa-cost-fault-tolerant-batch', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'quiz', 'mid', 2, 3, 'Công việc xử lý batch lớn, chịu được gián đoạn và có thể chạy lại. Lựa chọn rẻ nhất là gì?', 'Spot Instances rẻ nhất (giảm tới ~90%) và phù hợp workload chịu lỗi, có thể chạy lại khi bị thu hồi.', 'single_choice', '[{"key":"a","text":"On-Demand Instances"},{"key":"b","text":"Spot Instances"},{"key":"c","text":"Reserved Instances trả trước toàn bộ"},{"key":"d","text":"Dedicated Hosts"}]'::jsonb, '{b}'),
  ('saa-cost-right-sizing', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'quiz', 'mid', 2, 3, 'CloudWatch cho thấy nhiều EC2 chỉ dùng ~10% CPU và RAM liên tục. Hành động tối ưu chi phí phù hợp?', 'Right-sizing: chuyển sang instance type nhỏ hơn phù hợp mức sử dụng thực tế để cắt giảm chi phí mà vẫn đủ tài nguyên.', 'single_choice', '[{"key":"a","text":"Right-sizing xuống instance nhỏ hơn"},{"key":"b","text":"Nâng lên instance lớn hơn cho an toàn"},{"key":"c","text":"Mua thêm Reserved Instances cùng size"},{"key":"d","text":"Bật Multi-AZ cho tất cả instance"}]'::jsonb, '{a}'),
  ('saa-cost-compute-savings-plan-flexible', (select id from public.topics where slug = 'saa-cost-compute-pricing'), 'quiz', 'mid', 3, 3, 'Tổ chức muốn giảm giá compute nhưng vẫn linh hoạt đổi giữa EC2, Fargate và Lambda ở nhiều Region. Nên chọn gì?', 'Compute Savings Plans áp dụng linh hoạt cho EC2, Fargate và Lambda trên mọi Region/family, phù hợp khi cần linh hoạt cao.', 'single_choice', '[{"key":"a","text":"Standard Reserved Instances gắn family"},{"key":"b","text":"EC2 Instance Savings Plans một Region"},{"key":"c","text":"Compute Savings Plans"},{"key":"d","text":"Spot Instances cho mọi dịch vụ"}]'::jsonb, '{c}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-cost-optimized'), 'saa-cost-storage-lifecycle', 'Storage Cost & Lifecycle', 'mid', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-cost-s3-storage-classes', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'theory', 'mid', 3, 3, 'Kể tên các S3 storage class chính theo chi phí và tần suất truy cập.', 'S3 Standard cho dữ liệu truy cập thường xuyên. Standard-IA và One Zone-IA cho dữ liệu ít truy cập, rẻ hơn nhưng có phí retrieval. Glacier Instant Retrieval, Glacier Flexible Retrieval và Glacier Deep Archive cho lưu trữ dài hạn/archival với chi phí rất thấp nhưng thời gian truy xuất chậm dần. Intelligent-Tiering tự động chuyển dữ liệu giữa các tier theo pattern truy cập.', null, null, null),
  ('saa-cost-s3-lifecycle', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'theory', 'mid', 3, 3, 'S3 Lifecycle policy giúp tối ưu chi phí như thế nào?', 'Lifecycle policy tự động chuyển object sang storage class rẻ hơn theo thời gian (transition), ví dụ Standard sang Standard-IA sau 30 ngày rồi sang Glacier sau 90 ngày. Nó cũng có thể tự xóa (expiration) object cũ hoặc phiên bản cũ khi bật versioning. Nhờ đó giảm chi phí lưu trữ mà không cần thao tác thủ công.', null, null, null),
  ('saa-cost-ebs-snapshot-cost', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'theory', 'mid', 3, 3, 'EBS Snapshot ảnh hưởng chi phí ra sao và cách tối ưu?', 'EBS Snapshot là bản backup incremental lưu trên S3 do AWS quản lý, chỉ tính phí cho các block thay đổi nên tiết kiệm hơn full backup mỗi lần. Xóa snapshot cũ không cần thiết và dùng Amazon Data Lifecycle Manager để tự động hóa việc tạo/xóa giúp kiểm soát chi phí. Có thể chuyển snapshot sang Snapshot Archive tier cho lưu trữ dài hạn rẻ hơn.', null, null, null),
  ('saa-cost-archive-cheapest', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'quiz', 'mid', 2, 3, 'Dữ liệu tuân thủ pháp lý cần giữ 7 năm, gần như không bao giờ truy cập, chấp nhận truy xuất chậm nhiều giờ. Storage class rẻ nhất là gì?', 'S3 Glacier Deep Archive có chi phí lưu trữ thấp nhất, phù hợp archival dài hạn với thời gian truy xuất hàng giờ.', 'single_choice', '[{"key":"a","text":"S3 Standard"},{"key":"b","text":"S3 Standard-IA"},{"key":"c","text":"S3 Glacier Deep Archive"},{"key":"d","text":"S3 Intelligent-Tiering tier thường xuyên"}]'::jsonb, '{c}'),
  ('saa-cost-unknown-access-pattern', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'quiz', 'mid', 2, 3, 'Một bucket có pattern truy cập thay đổi và khó dự đoán, không muốn quản lý tier thủ công. Nên dùng gì để tối ưu chi phí?', 'S3 Intelligent-Tiering tự động chuyển object giữa các access tier theo pattern truy cập, tối ưu chi phí mà không cần quản lý thủ công.', 'single_choice', '[{"key":"a","text":"S3 One Zone-IA cố định"},{"key":"b","text":"S3 Intelligent-Tiering"},{"key":"c","text":"S3 Glacier Deep Archive"},{"key":"d","text":"S3 Standard cố định mãi mãi"}]'::jsonb, '{b}'),
  ('saa-cost-infrequent-access', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'quiz', 'mid', 3, 3, 'Log file được truy cập vài lần mỗi quý, cần độ bền cao trên nhiều AZ và chi phí lưu trữ thấp hơn Standard. Chọn class nào?', 'S3 Standard-IA rẻ hơn Standard cho dữ liệu ít truy cập, vẫn lưu trên nhiều AZ đảm bảo độ bền cao.', 'single_choice', '[{"key":"a","text":"S3 Standard"},{"key":"b","text":"S3 One Zone-IA"},{"key":"c","text":"S3 Standard-IA"},{"key":"d","text":"S3 Glacier Deep Archive"}]'::jsonb, '{c}'),
  ('saa-cost-s3-lifecycle-transition', (select id from public.topics where slug = 'saa-cost-storage-lifecycle'), 'quiz', 'mid', 2, 3, 'Muốn tự động chuyển object sang tier rẻ hơn sau 30 ngày và xóa sau 365 ngày. Cấu hình nào thực hiện điều này?', 'S3 Lifecycle policy cho phép định nghĩa rule transition và expiration tự động theo tuổi của object.', 'single_choice', '[{"key":"a","text":"S3 Lifecycle policy với transition và expiration"},{"key":"b","text":"S3 Cross-Region Replication"},{"key":"c","text":"S3 Versioning"},{"key":"d","text":"S3 Object Lock"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'saa-cost-optimized'), 'saa-cost-transfer-tools', 'Data Transfer & Cost Tools', 'mid', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('saa-cost-data-transfer-pricing', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'theory', 'mid', 3, 3, 'Nguyên tắc cơ bản về chi phí data transfer trong AWS.', 'Data transfer vào AWS (inbound) thường miễn phí, nhưng data transfer ra Internet (outbound/egress) bị tính phí và thường là khoản đáng kể. Truyền giữa các AZ hoặc giữa các Region cũng phát sinh phí, trong khi truyền trong cùng AZ qua private IP thường rẻ hoặc miễn phí. Thiết kế nên giảm egress ra Internet và lưu lượng cross-AZ/cross-Region không cần thiết.', null, null, null),
  ('saa-cost-cost-explorer', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'theory', 'mid', 2, 3, 'AWS Cost Explorer dùng để làm gì?', 'Cost Explorer là công cụ trực quan hóa và phân tích chi phí/sử dụng theo thời gian, cho phép lọc theo service, tag, account để tìm nguồn chi phí lớn. Nó cung cấp dự báo (forecast) và gợi ý mua Reserved Instances/Savings Plans để tiết kiệm. Đây là công cụ chính để hiểu và tối ưu chi tiêu tổng thể.', null, null, null),
  ('saa-cost-serverless-cost', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'theory', 'mid', 2, 3, 'Vì sao serverless như Lambda có thể tối ưu chi phí?', 'Lambda tính phí theo số lần gọi và thời gian thực thi (GB-giây), không tính khi không chạy nên không tốn tiền cho tài nguyên idle. Với workload gián đoạn, lưu lượng biến động hoặc thấp, mô hình pay-per-use này thường rẻ hơn việc giữ EC2 chạy liên tục. Ngoài ra không cần quản lý/hạ tầng máy chủ, giảm chi phí vận hành.', null, null, null),
  ('saa-cost-reduce-egress', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'quiz', 'mid', 3, 3, 'Website phục vụ nhiều nội dung tĩnh cho user toàn cầu, chi phí egress từ S3/EC2 ra Internet đang cao. Cách giảm chi phí hiệu quả?', 'Đặt CloudFront trước origin: nội dung cache tại edge giảm số lần lấy từ origin, và data transfer từ CloudFront có giá rẻ hơn cùng với việc giảm egress từ origin.', 'single_choice', '[{"key":"a","text":"Dùng CloudFront cache trước S3/EC2 origin"},{"key":"b","text":"Nhân bản dữ liệu ra mọi Region"},{"key":"c","text":"Tăng kích thước EC2 phục vụ nội dung"},{"key":"d","text":"Chuyển toàn bộ sang Standard-IA"}]'::jsonb, '{a}'),
  ('saa-cost-budget-alert', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'quiz', 'mid', 2, 3, 'Team muốn nhận cảnh báo khi chi phí tháng vượt ngưỡng đặt trước. Công cụ nào phù hợp?', 'AWS Budgets cho phép đặt ngưỡng chi phí/sử dụng và gửi cảnh báo (qua SNS/email) khi thực tế hoặc dự báo vượt ngưỡng.', 'single_choice', '[{"key":"a","text":"AWS Budgets với alert theo ngưỡng"},{"key":"b","text":"AWS CloudTrail"},{"key":"c","text":"Amazon Inspector"},{"key":"d","text":"AWS Config"}]'::jsonb, '{a}'),
  ('saa-cost-vpc-endpoint', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'quiz', 'mid', 3, 3, 'EC2 trong private subnet truy cập S3 qua NAT Gateway phát sinh phí xử lý và data transfer lớn. Cách giảm chi phí?', 'S3 Gateway VPC Endpoint cho phép truy cập S3 qua mạng riêng AWS, không đi qua NAT Gateway nên loại bỏ phí NAT và data transfer liên quan.', 'single_choice', '[{"key":"a","text":"Tăng số lượng NAT Gateway"},{"key":"b","text":"Dùng S3 Gateway VPC Endpoint"},{"key":"c","text":"Chuyển EC2 ra public subnet có IP public"},{"key":"d","text":"Bật S3 Transfer Acceleration"}]'::jsonb, '{b}'),
  ('saa-cost-trusted-advisor', (select id from public.topics where slug = 'saa-cost-transfer-tools'), 'quiz', 'mid', 2, 3, 'Muốn nhận khuyến nghị tự động về các cơ hội tiết kiệm chi phí như idle resource và Reserved Instance chưa dùng hết. Công cụ nào?', 'AWS Trusted Advisor cung cấp các check về cost optimization, phát hiện tài nguyên nhàn rỗi và gợi ý tiết kiệm.', 'single_choice', '[{"key":"a","text":"AWS Trusted Advisor"},{"key":"b","text":"AWS CloudFormation"},{"key":"c","text":"Amazon GuardDuty"},{"key":"d","text":"AWS Systems Manager"}]'::jsonb, '{a}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('pmp-people', 'People', (select id from public.tracks where slug = 'pmp'), 0, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-people'), 'pmp-people-leadership', 'Lãnh đạo & Servant Leadership', 'senior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-people-servant-leadership-la-gi', (select id from public.topics where slug = 'pmp-people-leadership'), 'theory', 'senior', 2, 3, 'Servant leadership là gì và vì sao PMBOK 7 nhấn mạnh nó cho project manager?', 'Servant leadership là phong cách lãnh đạo đặt nhu cầu của team lên trước, tập trung phục vụ, phát triển và loại bỏ trở ngại (impediments) cho thành viên. PM đóng vai trò facilitator, coach và người bảo vệ team hơn là ra lệnh (command-and-control). PMBOK 7 và Agile đề cao servant leadership vì nó tăng self-organization, ownership và hiệu suất bền vững của team.', null, null, null),
  ('pmp-people-leadership-vs-management', (select id from public.topics where slug = 'pmp-people-leadership'), 'theory', 'senior', 2, 3, 'Phân biệt leadership và management trong quản lý dự án.', 'Management thiên về sử dụng vị trí quyền lực (positional power) để chỉ đạo công việc, quy trình, kiểm soát và đạt kết quả dự đoán được. Leadership thiên về truyền cảm hứng, xây dựng tầm nhìn (vision), tạo động lực và dẫn dắt con người vượt qua thay đổi. PM giỏi cần cả hai: quản lý công việc và lãnh đạo con người, cân bằng tùy tình huống.', null, null, null),
  ('pmp-people-cac-nguon-quyen-luc', (select id from public.topics where slug = 'pmp-people-leadership'), 'theory', 'senior', 3, 3, 'Kể tên các dạng power (quyền lực) của PM và cho biết dạng nào thường hiệu quả nhất.', 'Các dạng chính gồm: positional/formal, reward, coercive/penalty, expert và referent power. Expert (chuyên môn) và referent (được tôn trọng, ngưỡng mộ) thường hiệu quả và bền vững nhất vì tạo ảnh hưởng tự nguyện. Coercive (trừng phạt) thường kém hiệu quả nhất và nên tránh lạm dụng.', null, null, null),
  ('pmp-people-situational-leadership', (select id from public.topics where slug = 'pmp-people-leadership'), 'theory', 'senior', 3, 3, 'Situational leadership khuyến nghị PM điều chỉnh phong cách theo yếu tố nào?', 'Situational leadership (Hersey-Blanchard) cho rằng PM nên điều chỉnh phong cách theo mức độ trưởng thành/năng lực và sự sẵn sàng (readiness) của từng thành viên hoặc tình huống. Với người mới, thiên về directing/coaching; với người thành thạo, chuyển sang supporting/delegating. Không có một phong cách lãnh đạo đúng cho mọi trường hợp.', null, null, null),
  ('pmp-people-leadership-thanh-vien-moi-tinh-huong', (select id from public.topics where slug = 'pmp-people-leadership'), 'quiz', 'senior', 3, 3, 'Tình huống: Một thành viên mới, chưa có kinh nghiệm với công nghệ của dự án, được giao một task quan trọng và tỏ ra lo lắng. Theo situational leadership, PM nên làm gì?', 'Với thành viên năng lực thấp nhưng nhiệm vụ quan trọng, phong cách directing/coaching (hướng dẫn cụ thể, kèm cặp sát) là phù hợp nhất; delegating chỉ dùng cho người đã thành thạo.', 'single_choice', '[{"key":"a","text":"Delegate hoàn toàn task để họ tự học và tự chịu trách nhiệm"},{"key":"b","text":"Áp dụng phong cách directing/coaching, hướng dẫn cụ thể và kèm cặp sát"},{"key":"c","text":"Chuyển task cho một thành viên senior để đảm bảo tiến độ"},{"key":"d","text":"Báo cáo sponsor rằng team thiếu năng lực"}]'::jsonb, '{b}'),
  ('pmp-people-servant-leadership-remove-impediment', (select id from public.topics where slug = 'pmp-people-leadership'), 'quiz', 'senior', 2, 3, 'Tình huống: Trong daily standup của một Agile team, một developer báo rằng họ bị chặn vì chưa được cấp quyền truy cập môi trường test suốt 2 ngày. Là servant leader, PM nên ưu tiên làm gì?', 'Servant leader tập trung loại bỏ impediment cho team; PM nên chủ động làm việc với bộ phận liên quan để khơi thông blocker càng sớm càng tốt, thay vì đổ lỗi hay chỉ ghi nhận.', 'single_choice', '[{"key":"a","text":"Ghi nhận vào risk log và chờ retrospective để bàn"},{"key":"b","text":"Yêu cầu developer tự liên hệ IT và tự giải quyết"},{"key":"c","text":"Chủ động làm việc với bộ phận IT để khơi thông quyền truy cập ngay"},{"key":"d","text":"Giảm scope của sprint để bỏ qua task bị chặn"}]'::jsonb, '{c}'),
  ('pmp-people-power-type-tinh-huong', (select id from public.topics where slug = 'pmp-people-leadership'), 'quiz', 'senior', 3, 3, 'Tình huống: PM muốn tạo ảnh hưởng để team tình nguyện làm thêm giờ trong giai đoạn nước rút mà không cưỡng ép. Dạng power nào nên dựa vào nhất?', 'Referent power (sự tôn trọng, ngưỡng mộ và tin tưởng dành cho PM) tạo ảnh hưởng tự nguyện tốt nhất; coercive power gây bất mãn và không bền vững.', 'single_choice', '[{"key":"a","text":"Coercive power (đe dọa hậu quả nếu không làm)"},{"key":"b","text":"Referent power (dựa vào sự tôn trọng và tin tưởng team dành cho PM)"},{"key":"c","text":"Positional power (ra lệnh vì là PM)"},{"key":"d","text":"Penalty power (trừ thưởng nếu từ chối)"}]'::jsonb, '{b}'),
  ('pmp-people-leadership-style-cross-functional', (select id from public.topics where slug = 'pmp-people-leadership'), 'quiz', 'senior', 3, 3, 'Tình huống: PM dẫn dắt một self-organizing, cross-functional team gồm các chuyên gia giàu kinh nghiệm. Phong cách lãnh đạo nào phù hợp nhất?', 'Với team trưởng thành và tự tổ chức, phong cách supporting/delegating kết hợp servant leadership giúp trao quyền và phát huy chuyên môn; micromanage sẽ làm giảm động lực.', 'single_choice', '[{"key":"a","text":"Micromanaging để kiểm soát chặt từng chi tiết"},{"key":"b","text":"Autocratic, tự ra mọi quyết định kỹ thuật"},{"key":"c","text":"Supporting/delegating kết hợp servant leadership, trao quyền cho team"},{"key":"d","text":"Laissez-faire hoàn toàn, không tham gia gì"}]'::jsonb, '{c}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-people'), 'pmp-people-conflict', 'Quản lý xung đột', 'senior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-people-5-cach-giai-quyet-xung-dot', (select id from public.topics where slug = 'pmp-people-conflict'), 'theory', 'senior', 3, 3, 'Kể tên 5 kỹ thuật giải quyết xung đột (conflict resolution) theo PMI và ý nghĩa.', 'Năm kỹ thuật gồm: Collaborate/Problem Solve (hợp tác tìm giải pháp win-win), Compromise/Reconcile (mỗi bên nhượng bộ một phần), Smooth/Accommodate (nhấn mạnh điểm chung, nhường bên kia), Force/Direct (áp đặt quan điểm, win-lose), và Withdraw/Avoid (né tránh, hoãn xung đột). Collaborate/Problem Solve thường cho kết quả tốt và bền vững nhất.', null, null, null),
  ('pmp-people-xung-dot-la-tot-hay-xau', (select id from public.topics where slug = 'pmp-people-conflict'), 'theory', 'senior', 2, 3, 'Theo quan điểm hiện đại của PMI, xung đột trong team là điều tốt hay xấu?', 'Quan điểm hiện đại xem xung đột là điều tự nhiên và không thể tránh khỏi khi có nhiều người làm việc cùng nhau. Nếu được quản lý tốt, xung đột mang tính xây dựng có thể thúc đẩy sáng tạo, cải thiện quyết định. Vấn đề không phải là loại bỏ xung đột mà là quản lý nó hiệu quả.', null, null, null),
  ('pmp-people-nguon-goc-xung-dot', (select id from public.topics where slug = 'pmp-people-conflict'), 'theory', 'senior', 3, 3, 'Những nguyên nhân xung đột phổ biến nhất trong dự án là gì?', 'Các nguồn xung đột phổ biến gồm: schedules (lịch trình), priorities (ưu tiên), resources (nguồn lực), technical opinions, administrative procedures, cost và personality. Nghiên cứu cho thấy schedules, priorities và resources thường là nguyên nhân hàng đầu, còn personality (tính cách cá nhân) thường ít phổ biến hơn nhưng khó xử lý nhất.', null, null, null),
  ('pmp-people-vai-tro-pm-khi-team-xung-dot', (select id from public.topics where slug = 'pmp-people-conflict'), 'theory', 'senior', 3, 3, 'Vai trò của PM khi hai thành viên team xảy ra xung đột là gì?', 'PM nên khuyến khích hai bên trực tiếp giải quyết vấn đề với nhau trước (ownership của người trong cuộc). Nếu không tự giải quyết được, PM mới can thiệp facilitate một cách kịp thời, riêng tư, tập trung vào vấn đề chứ không vào con người. Xung đột nên được xử lý sớm và trực tiếp.', null, null, null),
  ('pmp-people-xung-dot-nhom-tinh-huong', (select id from public.topics where slug = 'pmp-people-conflict'), 'quiz', 'senior', 3, 3, 'Tình huống: Hai kỹ sư trong team tranh cãi gay gắt về cách tiếp cận kỹ thuật, ảnh hưởng tiến độ. PM có thời gian và muốn giải pháp bền vững, đôi bên đồng thuận. PM nên dùng kỹ thuật nào?', 'Collaborate/Problem Solve tìm giải pháp win-win, giải quyết tận gốc và tạo cam kết cao nhất từ cả hai bên; đây là kỹ thuật được ưu tiên khi có đủ thời gian và cần kết quả bền vững.', 'single_choice', '[{"key":"a","text":"Withdraw/Avoid: hoãn cuộc tranh luận sang lúc khác"},{"key":"b","text":"Force/Direct: PM tự quyết định phương án và bắt hai bên theo"},{"key":"c","text":"Collaborate/Problem Solve: cùng phân tích để tìm giải pháp win-win"},{"key":"d","text":"Smooth/Accommodate: nhấn mạnh điểm chung và bỏ qua khác biệt"}]'::jsonb, '{c}'),
  ('pmp-people-xung-dot-khan-cap-force', (select id from public.topics where slug = 'pmp-people-conflict'), 'quiz', 'senior', 3, 3, 'Tình huống: Xảy ra sự cố production nghiêm trọng, hai thành viên tranh cãi về cách xử lý trong khi hệ thống đang down. Cần quyết định tức thì. Kỹ thuật nào phù hợp NHẤT lúc này?', 'Trong tình huống khẩn cấp cần quyết định ngay, Force/Direct (PM ra quyết định dứt khoát) là phù hợp vì thời gian là yếu tố then chốt, dù đây thường là giải pháp win-lose.', 'single_choice', '[{"key":"a","text":"Collaborate: tổ chức workshop để phân tích kỹ mọi phương án"},{"key":"b","text":"Force/Direct: PM ra quyết định dứt khoát để xử lý ngay"},{"key":"c","text":"Compromise: mỗi bên làm nửa giải pháp của mình"},{"key":"d","text":"Withdraw: chờ hai bên bình tĩnh rồi bàn lại"}]'::jsonb, '{b}'),
  ('pmp-people-xung-dot-nen-lam-gi-truoc', (select id from public.topics where slug = 'pmp-people-conflict'), 'quiz', 'senior', 3, 3, 'Tình huống: PM nghe tin đồn hai thành viên đang bất hòa nhưng công việc chưa bị ảnh hưởng rõ. PM nên làm gì TRƯỚC TIÊN?', 'PM nên khuyến khích hai bên tự trao đổi và giải quyết trực tiếp trước; xung đột nên được xử lý sớm, riêng tư và bởi chính người trong cuộc trước khi PM can thiệp sâu.', 'single_choice', '[{"key":"a","text":"Lập tức leo thang lên functional manager của cả hai"},{"key":"b","text":"Bỏ qua vì công việc chưa bị ảnh hưởng"},{"key":"c","text":"Khuyến khích hai bên trực tiếp trao đổi để tự giải quyết"},{"key":"d","text":"Chuyển một trong hai người sang team khác"}]'::jsonb, '{c}'),
  ('pmp-people-compromise-vs-collaborate', (select id from public.topics where slug = 'pmp-people-conflict'), 'quiz', 'senior', 4, 3, 'Tình huống: Deadline rất gần, hai bên bất đồng về scope một tính năng nhỏ, không đủ thời gian phân tích sâu và cả hai đều cần nhượng bộ để tiến tiếp. Kỹ thuật nào phù hợp nhất?', 'Compromise/Reconcile (lose-lose có kiểm soát) phù hợp khi thời gian hạn chế và cần giải pháp tạm chấp nhận được từ cả hai; Collaborate cần nhiều thời gian hơn.', 'single_choice', '[{"key":"a","text":"Collaborate: dành thêm nhiều buổi phân tích để tối ưu"},{"key":"b","text":"Compromise/Reconcile: mỗi bên nhượng bộ một phần để đạt thỏa thuận nhanh"},{"key":"c","text":"Withdraw: gác lại tính năng vô thời hạn"},{"key":"d","text":"Force: áp đặt quan điểm của bên có chức vụ cao hơn"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-people'), 'pmp-people-team-building', 'Xây dựng & phát triển team', 'senior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-people-tuckman-5-giai-doan', (select id from public.topics where slug = 'pmp-people-team-building'), 'theory', 'senior', 2, 3, 'Trình bày 5 giai đoạn phát triển nhóm theo mô hình Tuckman.', 'Mô hình Tuckman gồm: Forming (làm quen, còn dè dặt), Storming (xung đột, khác biệt quan điểm bộc lộ), Norming (hình thành chuẩn mực, hợp tác dần), Performing (hiệu suất cao, tự chủ) và Adjourning (giải tán khi dự án kết thúc). Team không nhất thiết đi tuyến tính và có thể quay lại giai đoạn trước khi có thành viên mới.', null, null, null),
  ('pmp-people-team-charter-la-gi', (select id from public.topics where slug = 'pmp-people-team-building'), 'theory', 'senior', 2, 3, 'Team charter là gì và nó giúp ích gì cho team?', 'Team charter là tài liệu do team cùng xây dựng, thiết lập các ground rules, giá trị chung, quy ước giao tiếp, tiêu chí ra quyết định và kỳ vọng về hành vi. Vì team tự tạo ra nó nên tạo cam kết (buy-in) và giảm xung đột. Nó là công cụ quan trọng để xây dựng văn hóa và sự gắn kết của team.', null, null, null),
  ('pmp-people-training-vs-team-building', (select id from public.topics where slug = 'pmp-people-team-building'), 'theory', 'senior', 3, 3, 'Phân biệt training và team-building activities trong phát triển team.', 'Training nhằm nâng cao năng lực và kỹ năng chuyên môn của cá nhân (kỹ thuật, quy trình). Team-building activities nhằm cải thiện quan hệ, sự tin tưởng và hợp tác giữa các thành viên (ví dụ kickoff, hoạt động chung). Cả hai đều là công cụ của Develop Team nhưng phục vụ mục tiêu khác nhau.', null, null, null),
  ('pmp-people-colocation-vs-virtual', (select id from public.topics where slug = 'pmp-people-team-building'), 'theory', 'senior', 2, 3, 'Colocation là gì và nó hỗ trợ team-building như thế nào?', 'Colocation (tight matrix) là bố trí các thành viên team làm việc cùng một địa điểm vật lý, ví dụ war room. Nó tăng giao tiếp trực tiếp, xây dựng quan hệ, giảm hiểu lầm và cải thiện tinh thần đồng đội. Ngược lại là virtual team, cần công cụ và ground rules giao tiếp bù đắp cho khoảng cách.', null, null, null),
  ('pmp-people-tuckman-storming-tinh-huong', (select id from public.topics where slug = 'pmp-people-team-building'), 'quiz', 'senior', 3, 3, 'Tình huống: Team vừa qua giai đoạn làm quen, giờ bắt đầu bộc lộ nhiều bất đồng, tranh cãi về vai trò và cách làm. Team đang ở giai đoạn Tuckman nào và PM nên làm gì?', 'Đây là giai đoạn Storming; PM nên facilitate, làm rõ vai trò, thiết lập ground rules và coaching để đưa team tiến tới Norming, thay vì né tránh hay trừng phạt xung đột.', 'single_choice', '[{"key":"a","text":"Forming: để team tự làm quen thêm, không can thiệp"},{"key":"b","text":"Storming: chủ động facilitate, làm rõ vai trò và ground rules"},{"key":"c","text":"Performing: giao toàn quyền và rút lui hoàn toàn"},{"key":"d","text":"Adjourning: chuẩn bị giải tán team"}]'::jsonb, '{b}'),
  ('pmp-people-ground-rules-vi-pham', (select id from public.topics where slug = 'pmp-people-team-building'), 'quiz', 'senior', 3, 3, 'Tình huống: Một thành viên liên tục đến muộn và ngắt lời người khác trong họp, vi phạm ground rules mà team đã thống nhất. PM nên làm gì?', 'Khi ground rules do chính team lập bị vi phạm, mọi thành viên (bao gồm PM) có trách nhiệm áp dụng; PM nên nhắc lại và củng cố ground rules với thành viên đó, tốt nhất là trao đổi riêng.', 'single_choice', '[{"key":"a","text":"Bỏ qua vì đó là chuyện nhỏ"},{"key":"b","text":"Đuổi thành viên khỏi dự án ngay"},{"key":"c","text":"Nhắc lại và củng cố ground rules đã thống nhất, trao đổi riêng với thành viên"},{"key":"d","text":"Báo cáo ngay lên sponsor để kỷ luật"}]'::jsonb, '{c}'),
  ('pmp-people-team-moi-thanh-vien-tuckman', (select id from public.topics where slug = 'pmp-people-team-building'), 'quiz', 'senior', 3, 3, 'Tình huống: Team đang ở giai đoạn Performing thì có 3 thành viên mới gia nhập. Điều gì có khả năng xảy ra với sự phát triển của team?', 'Việc thay đổi thành phần khiến team có thể quay lại các giai đoạn đầu (Forming/Storming) của Tuckman; PM cần hỗ trợ tái hòa nhập, làm rõ vai trò và ground rules cho thành viên mới.', 'single_choice', '[{"key":"a","text":"Team vẫn giữ nguyên Performing vì đã trưởng thành"},{"key":"b","text":"Team có thể lùi về Forming/Storming và cần được hỗ trợ tái hòa nhập"},{"key":"c","text":"Team lập tức nhảy tới Adjourning"},{"key":"d","text":"Không cần làm gì vì thành viên mới sẽ tự thích nghi"}]'::jsonb, '{b}'),
  ('pmp-people-team-building-kickoff', (select id from public.topics where slug = 'pmp-people-team-building'), 'quiz', 'senior', 2, 3, 'Tình huống: Một dự án mới khởi động với các thành viên chưa từng làm việc cùng nhau, đến từ nhiều phòng ban. PM nên ưu tiên hoạt động nào để đặt nền tảng hợp tác?', 'Tổ chức kickoff meeting và cùng team xây dựng team charter/ground rules ngay đầu dự án giúp thiết lập kỳ vọng chung, quan hệ và cam kết, hỗ trợ team vượt qua Forming nhanh hơn.', 'single_choice', '[{"key":"a","text":"Bắt tay vào code ngay để tiết kiệm thời gian"},{"key":"b","text":"Tổ chức kickoff và cùng xây dựng team charter, ground rules"},{"key":"c","text":"Chờ đến khi có xung đột mới tổ chức họp team"},{"key":"d","text":"Để mỗi phòng ban làm theo cách riêng của họ"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-people'), 'pmp-people-empowerment', 'Trao quyền team & stakeholder', 'senior', 3, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-people-empower-team-la-gi', (select id from public.topics where slug = 'pmp-people-empowerment'), 'theory', 'senior', 2, 3, 'Empowerment (trao quyền) cho team nghĩa là gì và mang lại lợi ích gì?', 'Empowerment là trao cho team quyền tự ra quyết định trong phạm vi công việc của họ, khuyến khích ownership và self-organization. PM tạo môi trường an toàn, cung cấp thông tin và nguồn lực để team tự chủ. Kết quả là tăng động lực, tốc độ ra quyết định và chất lượng, giảm phụ thuộc vào PM.', null, null, null),
  ('pmp-people-raci-la-gi', (select id from public.topics where slug = 'pmp-people-empowerment'), 'theory', 'senior', 2, 3, 'RACI chart là gì và dùng để làm gì trong quản lý con người?', 'RACI là một dạng Responsibility Assignment Matrix (RAM) phân định vai trò: Responsible (người thực hiện), Accountable (người chịu trách nhiệm cuối, chỉ một người), Consulted (được tham vấn hai chiều) và Informed (được thông báo một chiều). Nó làm rõ ai làm gì, tránh chồng chéo hoặc bỏ sót trách nhiệm và giảm xung đột về vai trò.', null, null, null),
  ('pmp-people-motivation-theories', (select id from public.topics where slug = 'pmp-people-empowerment'), 'theory', 'senior', 3, 3, 'Nêu ngắn gọn các lý thuyết động lực (motivation) quan trọng PM nên biết.', 'Maslow (tháp nhu cầu), Herzberg (hygiene factors vs motivators), McGregor (Theory X/Y), McClelland (nhu cầu thành tựu/quyền lực/liên kết) và Vroom (Expectancy theory). Điểm chung: lương/điều kiện chỉ ngăn bất mãn (hygiene), còn động lực thật đến từ sự công nhận, trách nhiệm, phát triển và ý nghĩa công việc. PM nên trao quyền và ghi nhận để tạo động lực nội tại.', null, null, null),
  ('pmp-people-decision-making-team', (select id from public.topics where slug = 'pmp-people-empowerment'), 'theory', 'senior', 3, 3, 'Vì sao PM nên khuyến khích ra quyết định theo nhóm thay vì luôn tự quyết?', 'Ra quyết định theo nhóm (group decision-making) tận dụng trí tuệ tập thể, tăng chất lượng và độ chính xác của quyết định, đồng thời tạo buy-in và cam kết thực thi cao hơn. Nó cũng phát triển năng lực và ownership của team. PM chỉ tự quyết khi khẩn cấp hoặc khi cần trách nhiệm cá nhân rõ ràng.', null, null, null),
  ('pmp-people-empower-quyet-dinh-ky-thuat', (select id from public.topics where slug = 'pmp-people-empowerment'), 'quiz', 'senior', 3, 3, 'Tình huống: Team liên tục hỏi PM về mọi quyết định kỹ thuật nhỏ, làm chậm công việc và khiến PM quá tải. PM nên làm gì để cải thiện lâu dài?', 'PM nên empower team, trao quyền tự quyết trong phạm vi kỹ thuật và thiết lập ranh giới rõ ràng; điều này thúc đẩy self-organization, giảm nút thắt và tăng ownership.', 'single_choice', '[{"key":"a","text":"Tiếp tục tự quyết mọi thứ để kiểm soát chất lượng"},{"key":"b","text":"Trao quyền cho team tự quyết định kỹ thuật trong ranh giới rõ ràng"},{"key":"c","text":"Yêu cầu team gửi email xin duyệt từng quyết định"},{"key":"d","text":"Thuê thêm một PM phụ để trả lời câu hỏi"}]'::jsonb, '{b}'),
  ('pmp-people-raci-vai-tro-khong-ro', (select id from public.topics where slug = 'pmp-people-empowerment'), 'quiz', 'senior', 3, 3, 'Tình huống: Nhiều task bị bỏ sót vì các thành viên tưởng người khác chịu trách nhiệm; vai trò không rõ ràng gây trễ tiến độ. Công cụ nào giúp PM giải quyết gốc rễ?', 'RACI/RAM làm rõ ai Responsible và Accountable cho từng công việc, loại bỏ nhầm lẫn vai trò và bỏ sót trách nhiệm.', 'single_choice', '[{"key":"a","text":"Gantt chart chi tiết hơn"},{"key":"b","text":"Risk register cập nhật thường xuyên"},{"key":"c","text":"RACI chart để phân định rõ vai trò và trách nhiệm"},{"key":"d","text":"Cost baseline chặt chẽ hơn"}]'::jsonb, '{c}'),
  ('pmp-people-motivation-cong-nhan', (select id from public.topics where slug = 'pmp-people-empowerment'), 'quiz', 'senior', 4, 3, 'Tình huống: Một developer giỏi bắt đầu mất động lực dù lương đã cạnh tranh thị trường. Theo lý thuyết Herzberg, PM nên tập trung vào điều gì?', 'Theo Herzberg, lương là hygiene factor chỉ ngăn bất mãn; động lực thật đến từ motivators như sự công nhận, trách nhiệm, cơ hội phát triển và công việc ý nghĩa. PM nên tăng các yếu tố này.', 'single_choice', '[{"key":"a","text":"Tăng lương thêm nữa để tạo động lực"},{"key":"b","text":"Cung cấp sự công nhận, trách nhiệm lớn hơn và cơ hội phát triển"},{"key":"c","text":"Cải thiện chỗ ngồi và điều kiện văn phòng"},{"key":"d","text":"Nhắc nhở về chính sách kỷ luật của công ty"}]'::jsonb, '{b}'),
  ('pmp-people-stakeholder-engagement-empower', (select id from public.topics where slug = 'pmp-people-empowerment'), 'quiz', 'senior', 3, 3, 'Tình huống: Một stakeholder quan trọng cảm thấy bị gạt ra ngoài và ít cam kết với dự án. PM nên làm gì để tăng mức độ engagement của họ?', 'PM nên chủ động thu hút stakeholder tham gia, tham vấn ý kiến và cho họ vai trò/ảnh hưởng phù hợp trong các quyết định liên quan; sự tham gia thực chất tạo ownership và cam kết cao hơn.', 'single_choice', '[{"key":"a","text":"Chỉ gửi báo cáo trạng thái định kỳ và giữ khoảng cách"},{"key":"b","text":"Chủ động tham vấn, mời họ tham gia quyết định liên quan để tạo ownership"},{"key":"c","text":"Bỏ qua vì họ không phải người ký quyết định cuối"},{"key":"d","text":"Đợi họ tự chủ động liên hệ nếu cần"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-people'), 'pmp-people-eq-communication', 'Trí tuệ cảm xúc, virtual team & đàm phán', 'senior', 4, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-people-emotional-intelligence-la-gi', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'theory', 'senior', 2, 3, 'Emotional intelligence (EQ) gồm những thành phần nào và vì sao quan trọng với PM?', 'EQ (theo Goleman) gồm: self-awareness, self-regulation, motivation, empathy và social skills. PM có EQ cao hiểu và điều tiết được cảm xúc bản thân, đọc hiểu cảm xúc người khác, từ đó xây dựng quan hệ, quản lý xung đột và tạo động lực tốt hơn. EQ là năng lực cốt lõi trong domain People.', null, null, null),
  ('pmp-people-active-listening', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'theory', 'senior', 2, 3, 'Active listening là gì và PM áp dụng nó thế nào?', 'Active listening là lắng nghe chủ động, tập trung hoàn toàn vào người nói, xác nhận hiểu đúng bằng cách paraphrase, đặt câu hỏi làm rõ và quan sát ngôn ngữ cơ thể. Nó giúp PM nắm bắt đầy đủ thông điệp (kể cả cảm xúc), giảm hiểu lầm và xây dựng lòng tin. Đây là kỹ năng giao tiếp then chốt của domain People.', null, null, null),
  ('pmp-people-virtual-team-thach-thuc', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'theory', 'senior', 3, 3, 'Virtual team đối mặt những thách thức nào và PM nên làm gì để khắc phục?', 'Virtual team gặp thách thức về khác biệt múi giờ, văn hóa, ngôn ngữ, thiếu giao tiếp phi ngôn ngữ và cảm giác cô lập, dễ gây hiểu lầm và giảm gắn kết. PM nên thiết lập communication ground rules rõ ràng, dùng công nghệ collaboration phù hợp, tạo cơ hội tương tác và chú trọng xây dựng lòng tin từ xa.', null, null, null),
  ('pmp-people-nguyen-tac-dam-phan', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'theory', 'senior', 3, 3, 'Nêu nguyên tắc đàm phán (negotiation) hiệu quả mà PM nên áp dụng.', 'Đàm phán hiệu quả hướng tới kết quả win-win: tách con người khỏi vấn đề, tập trung vào lợi ích (interests) thay vì lập trường (positions), tạo nhiều phương án cùng có lợi và dựa trên tiêu chí khách quan. PM nên chuẩn bị kỹ, hiểu nhu cầu các bên và giữ quan hệ lâu dài thay vì thắng bằng mọi giá.', null, null, null),
  ('pmp-people-eq-thanh-vien-cang-thang', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'quiz', 'senior', 3, 3, 'Tình huống: Trong một cuộc họp căng thẳng, một thành viên tức giận và lớn tiếng. PM cảm thấy bực nhưng cần xử lý chuyên nghiệp. Ứng dụng EQ, PM nên làm gì TRƯỚC?', 'Self-regulation (kiểm soát cảm xúc bản thân) và empathy giúp PM giữ bình tĩnh, lắng nghe để hiểu nguyên nhân cảm xúc của thành viên trước khi phản ứng; đây là biểu hiện của EQ cao.', 'single_choice', '[{"key":"a","text":"Đáp trả cứng rắn để khẳng định quyền lực"},{"key":"b","text":"Giữ bình tĩnh, tự điều tiết cảm xúc và lắng nghe để hiểu nguyên nhân"},{"key":"c","text":"Kết thúc họp ngay và bỏ đi"},{"key":"d","text":"Phớt lờ và tiếp tục agenda như không có gì"}]'::jsonb, '{b}'),
  ('pmp-people-virtual-team-hieu-lam', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'quiz', 'senior', 3, 3, 'Tình huống: Một virtual team trải trên 3 múi giờ thường xuyên hiểu lầm nhau qua email và cảm thấy rời rạc. PM nên ưu tiên hành động nào?', 'PM nên thiết lập communication ground rules rõ ràng, chọn kênh giao tiếp phù hợp (ưu tiên đồng bộ khi cần) và tạo cơ hội tương tác trực tiếp qua video để giảm hiểu lầm và tăng gắn kết cho virtual team.', 'single_choice', '[{"key":"a","text":"Yêu cầu tất cả chuyển sang một múi giờ chung"},{"key":"b","text":"Thiết lập communication ground rules và dùng video meeting để tăng tương tác"},{"key":"c","text":"Chỉ giao tiếp bằng email để có lưu vết"},{"key":"d","text":"Giảm số lần họp để tiết kiệm thời gian"}]'::jsonb, '{b}'),
  ('pmp-people-dam-phan-win-win', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'quiz', 'senior', 4, 3, 'Tình huống: PM và một functional manager tranh chấp về việc phân bổ một kỹ sư chủ chốt. Cả hai đều cần người này. PM nên tiếp cận đàm phán thế nào?', 'PM nên tập trung vào lợi ích (interests) của cả hai bên, tìm phương án sáng tạo win-win (ví dụ chia sẻ thời gian, sắp xếp lịch) thay vì cố thắng bằng lập trường cứng nhắc; điều này bảo toàn quan hệ lâu dài.', 'single_choice', '[{"key":"a","text":"Leo thang ngay lên sponsor để ép functional manager nhường"},{"key":"b","text":"Tập trung vào lợi ích chung, tìm phương án win-win như chia sẻ nguồn lực"},{"key":"c","text":"Kiên quyết giữ lập trường đòi 100% thời gian của kỹ sư"},{"key":"d","text":"Rút lui và tự xoay xở không cần kỹ sư đó"}]'::jsonb, '{b}'),
  ('pmp-people-empathy-hieu-suat-giam', (select id from public.topics where slug = 'pmp-people-eq-communication'), 'quiz', 'senior', 3, 3, 'Tình huống: Một thành viên vốn làm việc tốt bỗng giảm hiệu suất và hay lơ đãng trong vài tuần gần đây. PM nên làm gì ĐẦU TIÊN?', 'Vận dụng empathy và active listening, PM nên trao đổi riêng, chân thành để hiểu điều gì đang xảy ra với thành viên trước khi kết luận hay áp dụng biện pháp; nguyên nhân có thể là vấn đề cá nhân hoặc trở ngại công việc.', 'single_choice', '[{"key":"a","text":"Ghi nhận vào đánh giá hiệu suất và cảnh cáo chính thức"},{"key":"b","text":"Trao đổi riêng, lắng nghe để hiểu nguyên nhân đằng sau sự thay đổi"},{"key":"c","text":"Chuyển bớt việc của họ cho người khác mà không hỏi"},{"key":"d","text":"Công khai nhắc nhở trong cuộc họp team"}]'::jsonb, '{b}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('pmp-process', 'Process', (select id from public.tracks where slug = 'pmp'), 2, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-process'), 'pmp-process-scope-integration', 'Quản lý phạm vi & tích hợp', 'senior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-process-project-charter-la-gi', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'theory', 'senior', 2, 3, 'Project charter là gì và vai trò của nó trong quản lý tích hợp (integration)?', 'Project charter là tài liệu do sponsor phát hành, chính thức khởi tạo dự án và trao quyền (authority) cho project manager sử dụng nguồn lực tổ chức. Nó ghi nhận mục tiêu cấp cao, high-level requirements, milestone, ngân sách sơ bộ và các stakeholder chính. Đây là đầu ra của integration management, làm nền cho toàn bộ quá trình lập kế hoạch.', null, null, null),
  ('pmp-process-integrated-change-control-tinh-huong', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'quiz', 'senior', 3, 3, 'Tình huống: Trong dự án predictive, một stakeholder yêu cầu thêm tính năng mới sau khi scope baseline đã được duyệt. Project manager nên làm gì trước tiên?', 'Mọi thay đổi phải đi qua Perform Integrated Change Control: ghi nhận change request, đánh giá tác động tới scope/schedule/cost trước khi CCB phê duyệt. Không được tự ý thực hiện hay từ chối ngay.', 'single_choice', '[{"key":"a","text":"Thực hiện ngay để làm hài lòng stakeholder"},{"key":"b","text":"Từ chối vì baseline đã khóa"},{"key":"c","text":"Ghi nhận change request và đánh giá tác động qua integrated change control trước khi CCB duyệt"},{"key":"d","text":"Chuyển thẳng cho team lập trình xử lý ngoài kế hoạch"}]'::jsonb, '{c}'),
  ('pmp-process-wbs-la-gi', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'theory', 'senior', 2, 3, 'WBS (Work Breakdown Structure) là gì và nguyên tắc quan trọng nào cần tuân thủ?', 'WBS là phân rã có cấp bậc toàn bộ công việc dự án thành các deliverable nhỏ dần tới mức work package có thể ước lượng và giao được. Nguyên tắc 100% rule yêu cầu WBS bao gồm 100% công việc trong scope và không chứa công việc ngoài scope. Mức thấp nhất là work package, nền tảng cho ước lượng schedule và cost.', null, null, null),
  ('pmp-process-scope-creep-vs-gold-plating-tinh-huong', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'quiz', 'senior', 3, 3, 'Tình huống: Một lập trình viên tự ý thêm nhiều tính năng ''xịn'' mà khách hàng không yêu cầu, nghĩ rằng sẽ gây ấn tượng tốt. Đây là hiện tượng gì?', 'Đây là gold plating: nhóm tự thêm công việc vượt scope đã duyệt. Khác với scope creep (thay đổi không kiểm soát do yêu cầu bên ngoài), gold plating xuất phát từ chính nhóm và cần được ngăn chặn vì làm tăng rủi ro, chi phí mà không được phê duyệt.', 'single_choice', '[{"key":"a","text":"Scope creep"},{"key":"b","text":"Gold plating"},{"key":"c","text":"Progressive elaboration"},{"key":"d","text":"Rolling wave planning"}]'::jsonb, '{b}'),
  ('pmp-process-scope-baseline-gom-gi', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'theory', 'senior', 3, 3, 'Scope baseline gồm những thành phần nào?', 'Scope baseline là phiên bản đã được phê duyệt gồm ba thành phần: project scope statement, WBS và WBS dictionary. Nó chỉ được thay đổi thông qua formal change control và là chuẩn để đo lường hiệu suất phạm vi.', null, null, null),
  ('pmp-process-validate-scope-tinh-huong', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'quiz', 'senior', 3, 3, 'Tình huống: Deliverable đã qua kiểm tra chất lượng nội bộ (Control Quality). Bước tiếp theo để chính thức được khách hàng chấp nhận là gì?', 'Validate Scope là quá trình khách hàng/sponsor chính thức nghiệm thu (formal acceptance) các deliverable đã hoàn thành. Control Quality (kiểm tra tính đúng đắn nội bộ) thường diễn ra trước Validate Scope (nghiệm thu với khách hàng).', 'single_choice', '[{"key":"a","text":"Control Quality lại lần nữa"},{"key":"b","text":"Validate Scope để khách hàng nghiệm thu chính thức"},{"key":"c","text":"Close Project ngay lập tức"},{"key":"d","text":"Cập nhật risk register"}]'::jsonb, '{b}'),
  ('pmp-process-requirements-traceability-matrix', (select id from public.topics where slug = 'pmp-process-scope-integration'), 'theory', 'senior', 3, 3, 'Requirements Traceability Matrix (RTM) dùng để làm gì?', 'RTM là bảng liên kết mỗi requirement với nguồn gốc và với các deliverable, test case, mục tiêu kinh doanh tương ứng. Nó giúp đảm bảo mọi requirement đều được đáp ứng và kiểm chứng, đồng thời hỗ trợ đánh giá tác động khi có thay đổi.', null, null, null)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-process'), 'pmp-process-schedule', 'Quản lý tiến độ (schedule)', 'senior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-process-critical-path-la-gi', (select id from public.topics where slug = 'pmp-process-schedule'), 'theory', 'senior', 2, 3, 'Critical path là gì và ý nghĩa của nó với tiến độ dự án?', 'Critical path là chuỗi hoạt động dài nhất qua schedule network, xác định thời gian ngắn nhất để hoàn thành dự án. Các hoạt động trên critical path có total float bằng 0; bất kỳ chậm trễ nào ở đó sẽ trực tiếp làm chậm cả dự án.', null, null, null),
  ('pmp-process-total-float-tinh-huong', (select id from public.topics where slug = 'pmp-process-schedule'), 'quiz', 'senior', 3, 3, 'Tình huống: Một hoạt động có Early Start = ngày 5, Late Start = ngày 8. Total float của hoạt động này là bao nhiêu và nó có nằm trên critical path không?', 'Total float = Late Start − Early Start = 8 − 5 = 3 ngày. Vì float khác 0 nên hoạt động này KHÔNG nằm trên critical path; có thể trễ tối đa 3 ngày mà không làm chậm ngày kết thúc dự án.', 'single_choice', '[{"key":"a","text":"Float = 0, nằm trên critical path"},{"key":"b","text":"Float = 3, không nằm trên critical path"},{"key":"c","text":"Float = 13, nằm trên critical path"},{"key":"d","text":"Không đủ dữ liệu để tính"}]'::jsonb, '{b}'),
  ('pmp-process-crashing-vs-fast-tracking', (select id from public.topics where slug = 'pmp-process-schedule'), 'theory', 'senior', 3, 3, 'Phân biệt crashing và fast tracking trong nén tiến độ (schedule compression).', 'Crashing là thêm nguồn lực (nhân sự, overtime) để rút ngắn thời gian, thường làm tăng chi phí. Fast tracking là thực hiện song song các hoạt động vốn tuần tự, không tốn thêm chi phí nhưng làm tăng rủi ro và rework. Cả hai chỉ nén được thời gian trên critical path.', null, null, null),
  ('pmp-process-schedule-compression-tinh-huong', (select id from public.topics where slug = 'pmp-process-schedule'), 'quiz', 'senior', 3, 3, 'Tình huống: Dự án bị trễ, sponsor không cấp thêm ngân sách nhưng chấp nhận rủi ro cao hơn để về đích đúng hạn. Kỹ thuật nén tiến độ nào phù hợp nhất?', 'Fast tracking phù hợp vì thực hiện song song các hoạt động tuần tự mà không tăng chi phí, đổi lại chấp nhận rủi ro và khả năng rework cao hơn. Crashing sẽ làm tăng chi phí nên không phù hợp khi ngân sách bị khóa.', 'single_choice', '[{"key":"a","text":"Crashing"},{"key":"b","text":"Fast tracking"},{"key":"c","text":"Giảm scope không thông báo"},{"key":"d","text":"Kéo dài deadline"}]'::jsonb, '{b}'),
  ('pmp-process-rolling-wave-planning', (select id from public.topics where slug = 'pmp-process-schedule'), 'theory', 'senior', 2, 3, 'Rolling wave planning là gì?', 'Rolling wave planning là kỹ thuật lập kế hoạch theo tầng: công việc gần thì lập kế hoạch chi tiết, công việc xa thì để ở mức cao và được làm rõ dần (progressive elaboration) khi đến gần. Phù hợp khi thông tin đầu dự án chưa đầy đủ.', null, null, null),
  ('pmp-process-lead-vs-lag', (select id from public.topics where slug = 'pmp-process-schedule'), 'theory', 'senior', 3, 3, 'Phân biệt lead và lag trong quan hệ giữa các hoạt động.', 'Lead là khoảng thời gian mà hoạt động sau có thể bắt đầu sớm hơn so với hoạt động trước (tăng tốc, ví dụ Finish-to-Start với lead 2 ngày). Lag là độ trễ bắt buộc giữa hai hoạt động (ví dụ chờ bê tông khô 3 ngày). Lead rút ngắn, lag kéo dài lịch trình.', null, null, null),
  ('pmp-process-agile-velocity-burndown-tinh-huong', (select id from public.topics where slug = 'pmp-process-schedule'), 'quiz', 'senior', 3, 3, 'Tình huống: Trong dự án agile, team hoàn thành trung bình 30 story point mỗi sprint và backlog còn 120 point. Công cụ/chỉ số nào giúp dự báo còn bao nhiêu sprint để hoàn thành?', 'Velocity (30 point/sprint) kết hợp với product backlog còn lại cho phép ước lượng còn khoảng 4 sprint (120/30). Release burndown/burnup chart trực quan hóa tiến độ tiêu thụ backlog theo thời gian.', 'single_choice', '[{"key":"a","text":"Earned Value Management"},{"key":"b","text":"Velocity kết hợp burndown chart"},{"key":"c","text":"Critical path method"},{"key":"d","text":"Gantt chart tĩnh"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-process'), 'pmp-process-budget-evm', 'Quản lý chi phí & EVM', 'senior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-process-evm-pv-ev-ac', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'theory', 'senior', 3, 3, 'Giải thích ba giá trị cốt lõi của EVM: PV, EV và AC.', 'PV (Planned Value) là giá trị công việc dự kiến hoàn thành tới thời điểm đo. EV (Earned Value) là giá trị công việc thực tế đã hoàn thành, tính theo ngân sách. AC (Actual Cost) là chi phí thực đã chi cho phần công việc đó. So sánh ba giá trị này cho biết dự án đang vượt/thiếu ngân sách và nhanh/chậm tiến độ.', null, null, null),
  ('pmp-process-cpi-spi-tinh-huong', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'quiz', 'senior', 4, 3, 'Tình huống: Tại một mốc, EV = 35.000$, AC = 50.000$, PV = 40.000$. Tình trạng dự án là gì?', 'CPI = EV/AC = 35.000/50.000 = 0,70 (<1 → vượt ngân sách). SPI = EV/PV = 35.000/40.000 = 0,875 (<1 → chậm tiến độ). Dự án vừa vượt chi phí vừa trễ lịch.', 'single_choice', '[{"key":"a","text":"Đúng ngân sách, đúng tiến độ"},{"key":"b","text":"Vượt ngân sách (CPI=0,70) và chậm tiến độ (SPI=0,875)"},{"key":"c","text":"Tiết kiệm chi phí và vượt tiến độ"},{"key":"d","text":"Đúng ngân sách nhưng vượt tiến độ"}]'::jsonb, '{b}'),
  ('pmp-process-eac-cong-thuc', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'theory', 'senior', 3, 3, 'Công thức EAC (Estimate at Completion) phổ biến nhất khi variance hiện tại được coi là điển hình (typical) là gì?', 'Khi variance hiện tại được xem là điển hình cho phần còn lại, EAC = BAC / CPI. Cách này giả định hiệu suất chi phí trong tương lai sẽ tiếp tục như hiện tại. Nếu variance là bất thường (atypical), dùng EAC = AC + (BAC − EV).', null, null, null),
  ('pmp-process-eac-tinh-huong', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'quiz', 'senior', 4, 3, 'Tình huống: BAC = 200.000$, CPI hiện tại = 0,80 và xu hướng này được cho là sẽ tiếp tục. EAC ước tính là bao nhiêu?', 'EAC = BAC / CPI = 200.000 / 0,80 = 250.000$. Vì CPI < 1 và điển hình, dự án dự kiến hoàn thành với chi phí 250.000$, cao hơn ngân sách gốc 50.000$.', 'single_choice', '[{"key":"a","text":"160.000$"},{"key":"b","text":"200.000$"},{"key":"c","text":"250.000$"},{"key":"d","text":"50.000$"}]'::jsonb, '{c}'),
  ('pmp-process-contingency-vs-management-reserve', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'theory', 'senior', 4, 3, 'Phân biệt contingency reserve và management reserve; cái nào nằm trong cost baseline?', 'Contingency reserve dành cho các ''known unknowns'' (rủi ro đã xác định) và NẰM TRONG cost baseline, do PM quản lý. Management reserve dành cho ''unknown unknowns'' (rủi ro chưa lường trước), NẰM NGOÀI cost baseline nhưng trong tổng budget, và cần phê duyệt của quản lý cấp trên để sử dụng.', null, null, null),
  ('pmp-process-tcpi-tinh-huong', (select id from public.topics where slug = 'pmp-process-budget-evm'), 'quiz', 'senior', 4, 3, 'Tình huống: BAC = 100.000$, EV = 30.000$, AC = 40.000$. TCPI để hoàn thành đúng ngân sách BAC là bao nhiêu và điều đó nói lên gì?', 'TCPI = (BAC − EV) / (BAC − AC) = 70.000 / 60.000 ≈ 1,17. TCPI > 1 nghĩa là phần công việc còn lại phải làm hiệu quả hơn kế hoạch (chi phí thấp hơn) mới về đúng ngân sách — một mục tiêu khó.', 'single_choice', '[{"key":"a","text":"0,75 — dễ đạt"},{"key":"b","text":"1,17 — khó, cần hiệu suất cao hơn kế hoạch"},{"key":"c","text":"1,00 — đúng như kế hoạch"},{"key":"d","text":"0,86 — thoải mái về ngân sách"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-process'), 'pmp-process-risk-quality', 'Quản lý rủi ro & chất lượng', 'senior', 3, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-process-risk-response-negative', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'theory', 'senior', 3, 3, 'Kể tên các chiến lược ứng phó với rủi ro tiêu cực (threats) theo PMBOK.', 'Năm chiến lược cho threats gồm: Escalate (chuyển lên cấp cao hơn nếu ngoài thẩm quyền), Avoid (loại bỏ nguyên nhân), Transfer (chuyển rủi ro cho bên thứ ba như bảo hiểm, contract), Mitigate (giảm xác suất/tác động) và Accept (chấp nhận, chủ động hoặc bị động). Với opportunities có tập tương ứng: Escalate, Exploit, Share, Enhance, Accept.', null, null, null),
  ('pmp-process-risk-response-tinh-huong', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'quiz', 'senior', 2, 3, 'Tình huống: Có rủi ro cháy nổ ở kho hàng mà nhóm không thể loại bỏ. PM mua bảo hiểm để chuyển gánh nặng tài chính cho công ty bảo hiểm. Đây là chiến lược nào?', 'Đây là Transfer (chuyển giao): chuyển tác động tài chính của rủi ro sang bên thứ ba (bảo hiểm) mà không loại bỏ được bản thân rủi ro. Bảo hiểm và bảo lãnh hợp đồng là ví dụ điển hình của transfer.', 'single_choice', '[{"key":"a","text":"Avoid"},{"key":"b","text":"Mitigate"},{"key":"c","text":"Transfer"},{"key":"d","text":"Accept"}]'::jsonb, '{c}'),
  ('pmp-process-qualitative-vs-quantitative-risk', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'theory', 'senior', 3, 3, 'Phân biệt phân tích rủi ro định tính (qualitative) và định lượng (quantitative).', 'Qualitative risk analysis xếp hạng và ưu tiên rủi ro dựa trên xác suất và mức độ tác động (probability-impact matrix), mang tính chủ quan và nhanh. Quantitative risk analysis dùng số liệu và mô hình (Monte Carlo, EMV, decision tree) để định lượng tác động tổng hợp lên mục tiêu, thường chỉ áp dụng cho rủi ro ưu tiên cao.', null, null, null),
  ('pmp-process-emv-tinh-huong', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'quiz', 'senior', 3, 3, 'Tình huống: Một threat có xác suất 25% và tác động 80.000$. Expected Monetary Value (EMV) của rủi ro này là bao nhiêu?', 'EMV = xác suất × tác động = 0,25 × (−80.000$) = −20.000$ (giá trị âm vì là threat). EMV giúp so sánh và ưu tiên rủi ro cũng như định lượng contingency reserve.', 'single_choice', '[{"key":"a","text":"−20.000$"},{"key":"b","text":"−80.000$"},{"key":"c","text":"−5.000$"},{"key":"d","text":"+20.000$"}]'::jsonb, '{a}'),
  ('pmp-process-cost-of-quality', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'theory', 'senior', 3, 3, 'Cost of Quality (CoQ) gồm những loại chi phí nào?', 'CoQ gồm cost of conformance (phòng ngừa và thẩm định: training, testing, inspection) và cost of nonconformance (lỗi nội bộ như rework, scrap và lỗi bên ngoài như bảo hành, mất uy tín). Nguyên tắc: đầu tư phòng ngừa thường rẻ hơn nhiều so với chi phí sửa lỗi sau này.', null, null, null),
  ('pmp-process-secondary-vs-residual-risk', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'theory', 'senior', 4, 3, 'Phân biệt secondary risk và residual risk.', 'Secondary risk là rủi ro mới phát sinh trực tiếp từ việc triển khai một biện pháp ứng phó rủi ro. Residual risk là phần rủi ro còn sót lại sau khi đã áp dụng biện pháp ứng phó (thường được chấp nhận). Cả hai cần được ghi nhận và theo dõi trong risk register.', null, null, null),
  ('pmp-process-control-chart-rule-of-seven-tinh-huong', (select id from public.topics where slug = 'pmp-process-risk-quality'), 'quiz', 'senior', 4, 3, 'Tình huống: Trên control chart, dù các điểm đều nằm trong control limits nhưng 7 điểm liên tiếp đều nằm cùng một phía của đường trung bình. PM nên kết luận gì?', 'Theo rule of seven, bảy điểm liên tiếp cùng phía đường mean báo hiệu một xu hướng phi ngẫu nhiên (out of control) dù chưa vượt control limit. Cần điều tra nguyên nhân gán được (assignable cause) thay vì bỏ qua.', 'single_choice', '[{"key":"a","text":"Quá trình hoàn toàn ổn định, không cần làm gì"},{"key":"b","text":"Có xu hướng phi ngẫu nhiên (rule of seven), cần điều tra nguyên nhân"},{"key":"c","text":"Phải dừng dự án ngay lập tức"},{"key":"d","text":"Nới rộng control limits để các điểm hợp lệ"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-process'), 'pmp-process-delivery-engagement', 'Phương pháp, mua sắm & giao giá trị', 'senior', 4, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-process-predictive-agile-hybrid', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'theory', 'senior', 3, 3, 'Phân biệt cách tiếp cận predictive, agile và hybrid.', 'Predictive (waterfall) lập kế hoạch chi tiết trước, phù hợp khi requirements ổn định và ít thay đổi. Agile/adaptive giao giá trị theo từng vòng lặp ngắn (iteration/sprint), phù hợp khi requirements biến động và cần phản hồi liên tục. Hybrid kết hợp cả hai — ví dụ predictive cho hạ tầng, agile cho phần phát triển sản phẩm.', null, null, null),
  ('pmp-process-chon-methodology-tinh-huong', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'quiz', 'senior', 3, 3, 'Tình huống: Sản phẩm mới, requirements chưa rõ và thay đổi liên tục, khách hàng muốn thấy kết quả sớm và phản hồi thường xuyên. Cách tiếp cận nào phù hợp nhất?', 'Agile/adaptive phù hợp nhất vì giao giá trị theo iteration ngắn, cho phép inspect-and-adapt và tận dụng phản hồi khách hàng liên tục khi requirements còn nhiều bất định. Predictive phù hợp hơn khi scope ổn định.', 'single_choice', '[{"key":"a","text":"Predictive/waterfall thuần túy"},{"key":"b","text":"Agile/adaptive"},{"key":"c","text":"Không lập kế hoạch, làm tới đâu tính tới đó"},{"key":"d","text":"Khóa toàn bộ scope ngay từ đầu rồi mới bắt đầu"}]'::jsonb, '{b}'),
  ('pmp-process-contract-types-ffp-cpff-tm', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'theory', 'senior', 4, 3, 'So sánh ba loại hợp đồng FFP, CPFF và T&M về phân bổ rủi ro.', 'FFP (Firm Fixed Price): giá cố định, seller chịu rủi ro chi phí cao nhất, buyer rủi ro thấp — hợp khi scope rõ ràng. CPFF (Cost Plus Fixed Fee): buyer hoàn chi phí thực cộng phí cố định, buyer chịu rủi ro chi phí — hợp khi scope chưa chắc chắn. T&M (Time and Material): trả theo giờ và vật tư, dạng lai, hợp cho công việc nhỏ, khởi động nhanh hoặc staff augmentation.', null, null, null),
  ('pmp-process-procurement-tinh-huong', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'quiz', 'senior', 3, 3, 'Tình huống: Cần thuê gấp vài lập trình viên bổ sung trong thời gian ngắn khi khối lượng công việc chính xác chưa xác định. Loại hợp đồng nào phù hợp nhất?', 'Time and Material (T&M) phù hợp nhất: linh hoạt, khởi động nhanh và trả theo giờ khi khối lượng chưa xác định rõ. FFP đòi hỏi scope rõ ràng, còn CPFF thường dùng cho công việc lớn với chi phí khó dự đoán.', 'single_choice', '[{"key":"a","text":"Firm Fixed Price (FFP)"},{"key":"b","text":"Cost Plus Fixed Fee (CPFF)"},{"key":"c","text":"Time and Material (T&M)"},{"key":"d","text":"Cost Plus Incentive Fee (CPIF)"}]'::jsonb, '{c}'),
  ('pmp-process-communication-channels-formula', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'theory', 'senior', 3, 3, 'Công thức số kênh giao tiếp (communication channels) là gì và ý nghĩa quản lý?', 'Số kênh giao tiếp = n(n−1)/2, với n là số stakeholder. Ví dụ 6 người có 15 kênh, 10 người có 45 kênh. Số kênh tăng nhanh theo quy mô, nhấn mạnh nhu cầu lập communications management plan rõ ràng để tránh nhiễu và bỏ sót thông tin.', null, null, null),
  ('pmp-process-servant-leadership-mvp-tinh-huong', (select id from public.topics where slug = 'pmp-process-delivery-engagement'), 'quiz', 'senior', 3, 3, 'Tình huống: Trong dự án agile, thay vì ra lệnh, PM tập trung loại bỏ impediment, tạo điều kiện cho team tự tổ chức và ưu tiên giao một MVP để lấy phản hồi sớm. Phong cách và tư duy này thể hiện điều gì?', 'Đây là servant leadership kết hợp tư duy value delivery: lãnh đạo phục vụ nhóm (facilitate, remove blocker) và tối ưu giao giá trị sớm qua MVP để học hỏi từ phản hồi thực tế. Đây là trọng tâm của agile mindset trong PMBOK 7.', 'single_choice', '[{"key":"a","text":"Command-and-control leadership"},{"key":"b","text":"Servant leadership hướng value delivery"},{"key":"c","text":"Micromanagement"},{"key":"d","text":"Laissez-faire hoàn toàn buông lỏng"}]'::jsonb, '{b}')
insert into public.categories (slug, name, track_id, sort_order, is_published) values
  ('pmp-business-environment', 'Business Environment', (select id from public.tracks where slug = 'pmp'), 3, true)
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-business-environment'), 'pmp-be-compliance', 'Tuân thủ & quản trị (compliance)', 'senior', 0, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-be-compliance-la-gi', (select id from public.topics where slug = 'pmp-be-compliance'), 'theory', 'senior', 2, 3, 'Compliance trong quản lý dự án nghĩa là gì và tại sao quan trọng?', 'Compliance là việc đảm bảo dự án tuân thủ các luật, quy định, tiêu chuẩn ngành và chính sách nội bộ áp dụng (ví dụ an toàn, bảo mật dữ liệu, môi trường). Không tuân thủ có thể dẫn tới phạt pháp lý, mất uy tín hoặc phải dừng dự án, nên PM phải xác định và quản lý yêu cầu compliance ngay từ đầu.', null, null, null),
  ('pmp-be-compliance-regulatory-tinh-huong', (select id from public.topics where slug = 'pmp-be-compliance'), 'quiz', 'senior', 3, 3, 'Tình huống: Giữa dự án, một quy định pháp lý mới về bảo mật dữ liệu có hiệu lực và ảnh hưởng tới sản phẩm. PM nên làm gì đầu tiên?', 'PM cần phân tích tác động của yêu cầu compliance mới lên scope, schedule, cost và rủi ro, rồi đưa vào change control. Tuân thủ pháp lý là ràng buộc bắt buộc, không thể bỏ qua để giữ tiến độ.', 'single_choice', '[{"key":"a","text":"Phớt lờ vì dự án đã bắt đầu trước khi luật có hiệu lực"},{"key":"b","text":"Phân tích tác động của yêu cầu compliance và đưa vào change control"},{"key":"c","text":"Chờ tới khi bị kiểm tra rồi mới xử lý"},{"key":"d","text":"Giảm chất lượng để bù thời gian tuân thủ"}]'::jsonb, '{b}'),
  ('pmp-be-organizational-governance', (select id from public.topics where slug = 'pmp-be-compliance'), 'theory', 'senior', 3, 3, 'Organizational governance (quản trị tổ chức) ảnh hưởng thế nào tới dự án?', 'Governance là khung nguyên tắc, chính sách, cấu trúc quyền quyết định và cơ chế giám sát mà dự án phải tuân theo. Nó định hình cách phê duyệt, báo cáo, kiểm soát và gắn dự án với mục tiêu chiến lược. PM cần hiểu governance để escalate đúng cấp và tuân thủ quy trình phê duyệt.', null, null, null),
  ('pmp-be-non-compliance-risk-tinh-huong', (select id from public.topics where slug = 'pmp-be-compliance'), 'quiz', 'senior', 3, 3, 'Tình huống: Nhóm phát hiện một yêu cầu an toàn bắt buộc chưa được đáp ứng, nhưng đáp ứng nó sẽ làm trễ tiến độ. PM nên ưu tiên gì?', 'PM phải ưu tiên tuân thủ yêu cầu an toàn bắt buộc, ngay cả khi ảnh hưởng tiến độ, vì rủi ro pháp lý và an toàn con người vượt trên deadline. Sau đó minh bạch với stakeholder về tác động và điều chỉnh kế hoạch qua change control.', 'single_choice', '[{"key":"a","text":"Bỏ qua yêu cầu an toàn để giữ deadline"},{"key":"b","text":"Đáp ứng yêu cầu an toàn bắt buộc và điều chỉnh kế hoạch minh bạch"},{"key":"c","text":"Che giấu vấn đề với stakeholder"},{"key":"d","text":"Chuyển trách nhiệm cho nhà thầu phụ mà không xử lý"}]'::jsonb, '{b}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-business-environment'), 'pmp-be-benefits-value', 'Lợi ích & giá trị (benefits/value)', 'senior', 1, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-be-benefits-management-plan', (select id from public.topics where slug = 'pmp-be-benefits-value'), 'theory', 'senior', 3, 3, 'Benefits management plan là gì và gồm những nội dung chính nào?', 'Benefits management plan mô tả cách và thời điểm các lợi ích của dự án được hiện thực hóa và đo lường. Nó gồm target benefits, thời gian đạt được, metrics, người chịu trách nhiệm (benefits owner) và cách duy trì lợi ích sau khi dự án kết thúc. Nó gắn dự án với giá trị kinh doanh dài hạn.', null, null, null),
  ('pmp-be-benefits-realization-tinh-huong', (select id from public.topics where slug = 'pmp-be-benefits-value'), 'quiz', 'senior', 3, 3, 'Tình huống: Dự án đã bàn giao đúng scope, schedule, cost nhưng sau 6 tháng lợi ích kinh doanh kỳ vọng vẫn chưa xuất hiện. Điều này cho thấy điều gì?', 'Giao đúng ''iron triangle'' không đảm bảo benefits realization. Cần theo dõi lợi ích sau bàn giao qua benefits management plan; giá trị thực sự chỉ được xác nhận khi outcome kinh doanh (doanh thu, tiết kiệm, hài lòng khách hàng) thực sự đạt được.', 'single_choice', '[{"key":"a","text":"Dự án chắc chắn thành công vì đã đúng scope/schedule/cost"},{"key":"b","text":"Cần theo dõi benefits realization; giao đúng ràng buộc chưa đảm bảo tạo ra giá trị"},{"key":"c","text":"Lợi ích không liên quan tới trách nhiệm quản lý dự án"},{"key":"d","text":"Nên đóng hồ sơ và không đo lường thêm"}]'::jsonb, '{b}'),
  ('pmp-be-business-case-roi-npv', (select id from public.topics where slug = 'pmp-be-benefits-value'), 'theory', 'senior', 4, 3, 'Business case dùng để làm gì và các chỉ số ROI, NPV, payback period phản ánh điều gì?', 'Business case biện minh cho việc đầu tư dự án bằng cách so sánh chi phí với lợi ích kỳ vọng, làm cơ sở quyết định go/no-go. ROI đo tỷ suất lợi nhuận; NPV (Net Present Value) quy dòng tiền tương lai về hiện tại (NPV dương thì đáng đầu tư); payback period là thời gian thu hồi vốn. Business case cần được xem xét lại xuyên suốt dự án.', null, null, null),
  ('pmp-be-npv-lua-chon-tinh-huong', (select id from public.topics where slug = 'pmp-be-benefits-value'), 'quiz', 'senior', 3, 3, 'Tình huống: Công ty chọn giữa hai dự án loại trừ nhau: Dự án A có NPV = 120.000$, Dự án B có NPV = 90.000$. Chỉ dựa trên NPV thì nên chọn dự án nào?', 'Chọn Dự án A vì NPV cao hơn (120.000$ > 90.000$). NPV càng cao thì giá trị ròng tạo ra cho tổ chức càng lớn; khi hai dự án loại trừ nhau, ưu tiên NPV lớn hơn.', 'single_choice', '[{"key":"a","text":"Dự án A (NPV = 120.000$)"},{"key":"b","text":"Dự án B (NPV = 90.000$)"},{"key":"c","text":"Chọn dự án có NPV thấp hơn để an toàn"},{"key":"d","text":"Không đủ dữ liệu, NPV không dùng để so sánh"}]'::jsonb, '{a}')
insert into public.topics (category_id, slug, name, level, sort_order, is_published) values
  ((select id from public.categories where slug = 'pmp-business-environment'), 'pmp-be-change-external', 'Thay đổi tổ chức & yếu tố bên ngoài', 'senior', 2, true)
insert into public.questions (slug, topic_id, type, level, difficulty, frequency, prompt_md, answer_md, answer_format, options, correct_keys) values
  ('pmp-be-organizational-change-management', (select id from public.topics where slug = 'pmp-be-change-external'), 'theory', 'senior', 3, 3, 'Organizational change management là gì và mô hình ADKAR gồm những bước nào?', 'Organizational change management là cách chuẩn bị, trang bị và hỗ trợ con người áp dụng thay đổi để đạt kết quả mong muốn. Mô hình ADKAR gồm năm bước: Awareness (nhận thức nhu cầu), Desire (mong muốn), Knowledge (kiến thức cách thay đổi), Ability (khả năng thực hiện) và Reinforcement (củng cố để duy trì).', null, null, null),
  ('pmp-be-change-resistance-tinh-huong', (select id from public.topics where slug = 'pmp-be-change-external'), 'quiz', 'senior', 3, 3, 'Tình huống: Người dùng cuối kháng cự hệ thống mới vì sợ mất việc và chưa hiểu lợi ích. Hành động hiệu quả nhất của PM là gì?', 'PM nên tăng cường communication và engagement: giải thích rõ lợi ích (Awareness/Desire trong ADKAR), đào tạo và cho người dùng tham gia sớm để giảm kháng cự. Áp đặt hay phớt lờ sẽ làm thất bại việc adoption và không hiện thực hóa được lợi ích.', 'single_choice', '[{"key":"a","text":"Ép buộc triển khai và bỏ qua ý kiến người dùng"},{"key":"b","text":"Tăng communication, đào tạo và cho người dùng tham gia sớm"},{"key":"c","text":"Trì hoãn vô thời hạn cho tới khi hết kháng cự"},{"key":"d","text":"Giảm scope để tránh phải đào tạo"}]'::jsonb, '{b}'),
  ('pmp-be-eef-vs-opa', (select id from public.topics where slug = 'pmp-be-change-external'), 'theory', 'senior', 3, 3, 'Phân biệt Enterprise Environmental Factors (EEF) và Organizational Process Assets (OPA).', 'EEF là các điều kiện bên trong hoặc bên ngoài không do nhóm kiểm soát nhưng ảnh hưởng tới dự án (luật pháp, thị trường, văn hóa tổ chức, hạ tầng). OPA là tài sản quy trình của tổ chức có thể tái sử dụng (template, quy trình, bài học kinh nghiệm, kho dữ liệu lịch sử). EEF là ràng buộc, OPA là nguồn lực hỗ trợ.', null, null, null),
  ('pmp-be-external-factor-tinh-huong', (select id from public.topics where slug = 'pmp-be-change-external'), 'quiz', 'senior', 4, 3, 'Tình huống: Giữa dự án, một đối thủ tung ra sản phẩm mới và thị hiếu thị trường thay đổi, làm giảm giá trị của deliverable dự kiến. PM nên phản ứng thế nào?', 'Đây là external factor (EEF) tác động tới business case; PM cần đánh giá lại tính phù hợp và giá trị của dự án cùng sponsor, có thể điều chỉnh scope, ưu tiên lại hoặc thậm chí đề xuất dừng nếu dự án không còn tạo giá trị. Việc rà soát business case phải diễn ra liên tục, không chỉ ở đầu dự án.', 'single_choice', '[{"key":"a","text":"Tiếp tục nguyên kế hoạch bất kể thị trường thay đổi"},{"key":"b","text":"Đánh giá lại business case cùng sponsor và điều chỉnh hướng đi phù hợp giá trị"},{"key":"c","text":"Đổ lỗi cho đối thủ và không hành động"},{"key":"d","text":"Chỉ tập trung hoàn thành đúng scope gốc, bỏ qua giá trị"}]'::jsonb, '{b}')
